  { domain: 3, task: "3.3", q: "A company runs batch processing jobs that require high-performance CPUs. Which EC2 instance type should they choose?", opts: ["General purpose", "Compute optimized", "Memory optimized", "Storage optimized"], ans: 1, explain: "Compute optimized instances (C family) are ideal for workloads requiring high-performance processors, like batch processing." },
  { domain: 3, task: "3.3", q: "Which EC2 instance type is designed for large in-memory databases?", opts: ["Compute optimized", "Memory optimized", "Storage optimized", "General purpose"], ans: 1, explain: "Memory optimized instances (R and X families) are designed for workloads that require large amounts of memory, like in-memory databases." },
  { domain: 3, task: "3.3", q: "What is AWS Lambda?", opts: ["A virtual server service", "A serverless compute service that runs code in response to events", "A container orchestration service", "A database service"], ans: 1, explain: "AWS Lambda is a serverless compute service that runs code in response to events without provisioning or managing servers." },
  { domain: 3, task: "3.3", q: "Which service runs containers without managing the underlying infrastructure?", opts: ["Amazon EC2", "Amazon ECS with EC2 launch type", "AWS Fargate", "Amazon Lightsail"], ans: 2, explain: "AWS Fargate is a serverless compute engine for containers that removes the need to manage the underlying server infrastructure." },
  { domain: 3, task: "3.3", q: "What is the maximum execution time for a single AWS Lambda function invocation?", opts: ["5 minutes", "10 minutes", "15 minutes", "60 minutes"], ans: 2, explain: "AWS Lambda functions have a maximum execution timeout of 15 minutes per invocation." },
  { domain: 3, task: "3.3", q: "Which load balancer operates at the application layer (Layer 7) and supports path-based routing?", opts: ["Network Load Balancer", "Application Load Balancer", "Classic Load Balancer", "Gateway Load Balancer"], ans: 1, explain: "The Application Load Balancer (ALB) operates at Layer 7 and supports advanced routing features like path-based and host-based routing." },
  { domain: 3, task: "3.3", q: "Which load balancer is best for ultra-high performance and TCP/UDP traffic?", opts: ["Application Load Balancer", "Network Load Balancer", "Classic Load Balancer", "Gateway Load Balancer"], ans: 1, explain: "The Network Load Balancer (NLB) operates at Layer 4, handles millions of requests per second, and is optimized for TCP/UDP traffic." },
  { domain: 3, task: "3.3", q: "What does Amazon EC2 Auto Scaling do?", opts: ["Automatically patches EC2 instances", "Automatically adjusts the number of EC2 instances based on demand", "Automatically migrates instances between Regions", "Automatically optimizes instance costs"], ans: 1, explain: "EC2 Auto Scaling automatically adjusts the number of running EC2 instances based on defined conditions to match demand." },
  { domain: 3, task: "3.3", q: "Which container orchestration service is compatible with Kubernetes?", opts: ["Amazon ECS", "Amazon EKS", "AWS Fargate", "AWS Batch"], ans: 1, explain: "Amazon Elastic Kubernetes Service (EKS) is a managed Kubernetes service for running Kubernetes on AWS." },
  { domain: 3, task: "3.3", q: "A company needs to run machine learning training jobs that require GPU instances. Which EC2 instance type should they use?", opts: ["General purpose", "Compute optimized", "Accelerated computing", "Storage optimized"], ans: 2, explain: "Accelerated computing instances (P and G families) provide GPU capabilities for machine learning, graphics processing, and other GPU-intensive workloads." },
  { domain: 3, task: "3.3", q: "Which service is best for running large-scale parallel batch computing jobs?", opts: ["AWS Lambda", "Amazon EC2", "AWS Batch", "Amazon ECS"], ans: 2, explain: "AWS Batch dynamically provisions compute resources and manages job scheduling for batch computing workloads." },
  { domain: 3, task: "3.3", q: "What is Amazon ECS?", opts: ["A serverless compute service", "A fully managed container orchestration service", "A Kubernetes distribution", "A virtual machine service"], ans: 1, explain: "Amazon Elastic Container Service (ECS) is a fully managed container orchestration service for deploying and managing Docker containers." },
  { domain: 3, task: "3.3", q: "Which of the following are valid EC2 Auto Scaling policies? (Choose TWO)", opts: ["Target tracking scaling", "Manual scaling via CloudFormation only", "Step scaling", "Region-based scaling", "Account-based scaling"], ans: [0, 2], multi: true, explain: "Target tracking scaling adjusts capacity to maintain a target metric, and step scaling adjusts capacity in steps based on alarm thresholds." },
  { domain: 3, task: "3.3", q: "A startup wants to run a web application with unpredictable traffic. Which compute approach is MOST cost-effective?", opts: ["EC2 Reserved Instances", "AWS Lambda with API Gateway", "EC2 On-Demand Instances with fixed count", "Amazon Lightsail"], ans: 1, explain: "Lambda is most cost-effective for unpredictable traffic since you only pay for actual compute time used, with automatic scaling." },
  { domain: 3, task: "3.3", q: "What is the key difference between ECS and EKS?", opts: ["ECS is serverless; EKS is not", "ECS uses AWS-native orchestration; EKS uses Kubernetes", "ECS is for Windows containers only; EKS is for Linux only", "ECS is free; EKS has a per-cluster charge"], ans: 1, explain: "ECS uses AWS's proprietary container orchestration, while EKS uses the open-source Kubernetes orchestration platform." },
  { domain: 3, task: "3.3", q: "Which EC2 instance type is ideal for data warehousing workloads requiring high sequential read/write access to large datasets?", opts: ["General purpose", "Compute optimized", "Memory optimized", "Storage optimized"], ans: 3, explain: "Storage optimized instances (I and D families) provide high sequential read/write access to large datasets on local storage." },
  { domain: 3, task: "3.3", q: "What happens to data on an EC2 instance store when the instance is stopped?", opts: ["Data is preserved", "Data is automatically backed up to S3", "Data is lost", "Data is moved to EBS"], ans: 2, explain: "Instance store data is ephemeral and is lost when the instance is stopped, terminated, or the underlying hardware fails." },
  { domain: 3, task: "3.3", q: "Which service provides simple virtual private servers with bundled resources and a predictable monthly price?", opts: ["Amazon EC2", "Amazon Lightsail", "AWS Fargate", "AWS Lambda"], ans: 1, explain: "Amazon Lightsail provides simple virtual servers with bundled compute, storage, and networking at a low, predictable monthly price." },
  { domain: 3, task: "3.3", q: "What is the purpose of an Elastic Load Balancer?", opts: ["To store static content", "To distribute incoming traffic across multiple targets", "To encrypt data at rest", "To manage DNS records"], ans: 1, explain: "Elastic Load Balancing distributes incoming application traffic across multiple targets such as EC2 instances, containers, and IP addresses." },
  { domain: 3, task: "3.3", q: "A company runs Docker containers and wants AWS to manage the servers. Which launch type should they use with ECS?", opts: ["EC2 launch type", "Fargate launch type", "Lambda launch type", "Lightsail launch type"], ans: 1, explain: "The Fargate launch type with ECS runs containers without managing the underlying EC2 instances." },
  { domain: 3, task: "3.3", q: "Which of the following are benefits of AWS Lambda? (Choose TWO)", opts: ["No server management required", "Unlimited execution duration", "Automatic scaling", "Always-on compute capacity", "Support for bare metal workloads"], ans: [0, 2], multi: true, explain: "Lambda requires no server management and automatically scales to handle any number of concurrent requests." },
  { domain: 3, task: "3.3", q: "An Auto Scaling group has a minimum of 2, desired of 4, and maximum of 8 instances. How many instances will run under normal conditions?", opts: ["2", "4", "8", "6"], ans: 1, explain: "Under normal conditions, Auto Scaling maintains the desired capacity, which is 4 instances." },
  { domain: 3, task: "3.3", q: "Which ALB feature allows routing requests to different target groups based on the URL path?", opts: ["Sticky sessions", "Path-based routing", "Cross-zone load balancing", "SSL termination"], ans: 1, explain: "ALB path-based routing directs requests to different target groups based on the URL path (e.g., /api vs /images)." },
  { domain: 3, task: "3.3", q: "A media processing workload requires instances with high-performance local NVMe storage. Which instance type is best?", opts: ["T3 (general purpose)", "C5 (compute optimized)", "I3 (storage optimized)", "R5 (memory optimized)"], ans: 2, explain: "I3 storage optimized instances provide high-performance NVMe SSD local storage for I/O-intensive workloads." },
  { domain: 3, task: "3.3", q: "Which compute service is best suited for running a 3-second image processing function triggered by S3 uploads?", opts: ["Amazon EC2", "AWS Lambda", "Amazon ECS", "Amazon Lightsail"], ans: 1, explain: "Lambda is ideal for short-duration, event-driven tasks like image processing triggered by S3 events." },
  { domain: 3, task: "3.3", q: "What does the Network Load Balancer support that the Application Load Balancer does not?", opts: ["HTTPS traffic", "Static IP addresses", "Path-based routing", "WebSocket connections"], ans: 1, explain: "NLB supports static IP addresses (and Elastic IP addresses), which ALB does not natively support." },
  { domain: 3, task: "3.3", q: "Which scaling approach adds resources BEFORE demand increases based on predicted patterns?", opts: ["Reactive scaling", "Predictive scaling", "Manual scaling", "Scheduled scaling"], ans: 1, explain: "Predictive scaling uses machine learning to analyze historical patterns and proactively scale resources before demand increases." },
  { domain: 3, task: "3.3", q: "A company needs to run thousands of short-lived batch jobs with varying resource requirements. Which service handles this?", opts: ["Amazon EC2 with manual management", "AWS Batch", "AWS Lambda", "Amazon ECS"], ans: 1, explain: "AWS Batch automatically provisions optimal compute resources and manages job queues for batch computing workloads." },
  { domain: 3, task: "3.3", q: "Which compute option provides the MOST control over the underlying infrastructure?", opts: ["AWS Lambda", "AWS Fargate", "Amazon EC2", "Amazon Lightsail"], ans: 2, explain: "EC2 provides the most control, allowing you to choose instance types, operating systems, storage, and networking configurations." },
  { domain: 3, task: "3.3", q: "A company is migrating a legacy application that requires a specific OS kernel version. Which service is most appropriate?", opts: ["AWS Lambda", "Amazon EC2", "AWS Fargate", "Amazon Lightsail"], ans: 1, explain: "EC2 provides full control over the operating system, allowing you to use specific kernel versions for legacy applications." },
  { domain: 3, task: "3.3", q: "What is the relationship between Fargate and ECS/EKS?", opts: ["Fargate replaces ECS and EKS", "Fargate is a serverless compute engine that can be used with ECS or EKS", "Fargate is a container image repository", "Fargate is a load balancing service for containers"], ans: 1, explain: "Fargate is a serverless compute engine that works with both ECS and EKS to run containers without managing servers." },
  { domain: 3, task: "3.3", q: "Which of the following triggers can invoke AWS Lambda? (Choose TWO)", opts: ["Amazon S3 events", "Manual SSH connection", "Amazon DynamoDB Streams", "RDP connection", "Physical button press on hardware"], ans: [0, 2], multi: true, explain: "Lambda can be triggered by many AWS services including S3 events and DynamoDB Streams." },
  { domain: 3, task: "3.3", q: "A company wants to run containers and already has Kubernetes expertise. Which service should they choose?", opts: ["Amazon ECS", "Amazon EKS", "AWS Lambda", "Amazon Lightsail"], ans: 1, explain: "Amazon EKS is the managed Kubernetes service, ideal for teams with existing Kubernetes expertise." },
  { domain: 3, task: "3.3", q: "What is the main advantage of using Auto Scaling with an ELB?", opts: ["It reduces the cost of the load balancer", "It automatically registers and deregisters instances as they scale", "It eliminates the need for health checks", "It provides SSL certificates"], ans: 1, explain: "Auto Scaling automatically registers new instances with the ELB and deregisters terminated instances, ensuring traffic is properly distributed." },
  { domain: 3, task: "3.3", q: "Which EC2 instance family prefix indicates general purpose instances?", opts: ["C", "R", "M/T", "I"], ans: 2, explain: "M and T families are general purpose instances providing a balance of compute, memory, and networking." },
  { domain: 3, task: "3.3", q: "A workload has steady baseline CPU usage with occasional spikes. Which instance type is MOST cost-effective?", opts: ["M5 (general purpose)", "T3 (burstable)", "C5 (compute optimized)", "R5 (memory optimized)"], ans: 1, explain: "T3 burstable instances are cost-effective for workloads with steady baselines and occasional CPU spikes, using CPU credits for bursts." },
  { domain: 3, task: "3.3", q: "Which compute service has NO minimum fee or idle cost when no code is running?", opts: ["Amazon EC2", "Amazon ECS on EC2", "AWS Lambda", "Amazon Lightsail"], ans: 2, explain: "Lambda charges only for actual compute time consumed; there is no charge when code is not running." },
  { domain: 3, task: "3.3", q: "What is a Launch Template in the context of EC2 Auto Scaling?", opts: ["A pre-built application deployment package", "A template that defines instance configuration for Auto Scaling groups", "A CloudFormation template", "A pricing plan for EC2"], ans: 1, explain: "A Launch Template defines the instance configuration (AMI, instance type, security groups, etc.) used by Auto Scaling groups to launch instances." },
  { domain: 3, task: "3.3", q: "Which load balancer type should be used for third-party virtual appliances like firewalls?", opts: ["Application Load Balancer", "Network Load Balancer", "Gateway Load Balancer", "Classic Load Balancer"], ans: 2, explain: "Gateway Load Balancer is designed to deploy, scale, and manage third-party virtual appliances like firewalls and intrusion detection systems." },
  { domain: 3, task: "3.3", q: "A company needs to process millions of requests per second with static IP addresses. Which ELB type should they use?", opts: ["Application Load Balancer", "Network Load Balancer", "Classic Load Balancer", "Gateway Load Balancer"], ans: 1, explain: "NLB handles millions of requests per second with ultra-low latency and supports static/Elastic IP addresses." },
  { domain: 3, task: "3.3", q: "Which of the following are compute services? (Choose TWO)", opts: ["Amazon S3", "AWS Lambda", "Amazon RDS", "Amazon EC2", "Amazon Route 53"], ans: [1, 3], multi: true, explain: "Lambda and EC2 are compute services. S3 is storage, RDS is database, and Route 53 is DNS." },
  { domain: 3, task: "3.3", q: "What is the benefit of Savings Plans for compute?", opts: ["Free compute for 1 year", "Discounted pricing in exchange for a commitment to consistent compute usage", "Unlimited Lambda invocations", "Free data transfer"], ans: 1, explain: "Compute Savings Plans offer significant discounts (up to 66%) in exchange for a commitment to a consistent amount of compute usage over 1 or 3 years." },
  { domain: 3, task: "3.3", q: "Which service automatically handles compute resource provisioning for containerized batch jobs?", opts: ["Amazon ECS", "AWS Batch", "AWS Lambda", "Amazon EKS"], ans: 1, explain: "AWS Batch automatically provisions the optimal quantity and type of compute resources based on the volume and requirements of submitted batch jobs." },
  { domain: 3, task: "3.3", q: "A scientific research team needs GPU instances for deep learning model training. Which instance family should they use?", opts: ["M5", "C5", "P4", "T3"], ans: 2, explain: "P4 instances are accelerated computing instances with powerful GPUs, designed for machine learning training and HPC workloads." },
  { domain: 3, task: "3.3", q: "What does horizontal scaling mean in the context of Auto Scaling?", opts: ["Increasing the size of existing instances", "Adding more instances to handle increased load", "Moving to a different Region", "Upgrading the operating system"], ans: 1, explain: "Horizontal scaling (scaling out) adds more instances to distribute the load, as opposed to vertical scaling which increases the size of existing instances." },
  { domain: 3, task: "3.3", q: "Which feature of ALB allows routing to different target groups based on the hostname in the request?", opts: ["Path-based routing", "Host-based routing", "IP-based routing", "Query string routing"], ans: 1, explain: "ALB host-based routing routes requests to different target groups based on the hostname (e.g., api.example.com vs www.example.com)." },
  { domain: 3, task: "3.3", q: "A company runs a stateless web application. Which combination provides high availability and automatic scaling?", opts: ["Single EC2 instance with EBS", "Auto Scaling group with ALB across multiple AZs", "Lambda with S3", "Lightsail with manual failover"], ans: 1, explain: "An Auto Scaling group with ALB across multiple AZs provides both automatic scaling and high availability for stateless web applications." },
  { domain: 3, task: "3.3", q: "What is the purpose of an EC2 placement group?", opts: ["To organize instances by cost", "To influence the placement of instances to meet specific requirements like low latency", "To group instances by Region", "To assign security policies"], ans: 1, explain: "Placement groups influence the placement of instances to achieve low latency (cluster), high availability (spread), or partitioned workloads (partition)." },

  // ==================== TASK 3.4: Database Services (40 questions) ====================
  { domain: 3, task: "3.4", q: "Which AWS service is a fully managed relational database service?", opts: ["Amazon DynamoDB", "Amazon RDS", "Amazon ElastiCache", "Amazon Redshift"], ans: 1, explain: "Amazon RDS is a fully managed relational database service supporting MySQL, PostgreSQL, MariaDB, Oracle, SQL Server, and Aurora." },
  { domain: 3, task: "3.4", q: "What type of database is Amazon DynamoDB?", opts: ["Relational database", "Graph database", "NoSQL key-value and document database", "Data warehouse"], ans: 2, explain: "DynamoDB is a fully managed NoSQL database that supports key-value and document data models with single-digit millisecond performance." },
  { domain: 3, task: "3.4", q: "Which database service is AWS's MySQL and PostgreSQL-compatible relational database with up to 5x better performance?", opts: ["Amazon RDS", "Amazon Aurora", "Amazon Redshift", "Amazon Neptune"], ans: 1, explain: "Amazon Aurora is a MySQL and PostgreSQL-compatible relational database with up to 5x the throughput of standard MySQL." },
  { domain: 3, task: "3.4", q: "A company needs a data warehouse for complex analytical queries across petabytes of data. Which service should they use?", opts: ["Amazon RDS", "Amazon DynamoDB", "Amazon Redshift", "Amazon ElastiCache"], ans: 2, explain: "Amazon Redshift is a fully managed data warehouse designed for fast analytics across petabytes of structured data." },
  { domain: 3, task: "3.4", q: "Which service provides in-memory caching to improve application performance?", opts: ["Amazon RDS", "Amazon ElastiCache", "Amazon DynamoDB", "Amazon Aurora"], ans: 1, explain: "Amazon ElastiCache provides in-memory caching with Redis or Memcached to improve application performance by reducing database load." },
  { domain: 3, task: "3.4", q: "What is Amazon Neptune used for?", opts: ["Relational data storage", "Graph database workloads", "In-memory caching", "Data warehousing"], ans: 1, explain: "Amazon Neptune is a fully managed graph database service for building applications with highly connected datasets like social networks and knowledge graphs." },
  { domain: 3, task: "3.4", q: "Which service is best for migrating databases to AWS?", opts: ["AWS DataSync", "AWS Database Migration Service (DMS)", "AWS Transfer Family", "AWS Snowball"], ans: 1, explain: "AWS DMS migrates databases to AWS quickly and securely, with the source database remaining fully operational during migration." },
  { domain: 3, task: "3.4", q: "What is the key advantage of Amazon Aurora over standard RDS MySQL?", opts: ["Lower cost", "Up to 5x better performance and automatic storage scaling", "Support for NoSQL queries", "Built-in machine learning"], ans: 1, explain: "Aurora provides up to 5x the performance of standard MySQL, with automatic storage scaling up to 128 TB." },
  { domain: 3, task: "3.4", q: "Which database service provides an immutable, cryptographically verifiable transaction log?", opts: ["Amazon DynamoDB", "Amazon QLDB", "Amazon Neptune", "Amazon DocumentDB"], ans: 1, explain: "Amazon QLDB (Quantum Ledger Database) provides an immutable, transparent, and cryptographically verifiable transaction log." },
  { domain: 3, task: "3.4", q: "A company needs a MongoDB-compatible document database. Which AWS service should they use?", opts: ["Amazon DynamoDB", "Amazon DocumentDB", "Amazon Neptune", "Amazon RDS"], ans: 1, explain: "Amazon DocumentDB is a MongoDB-compatible document database service designed for JSON data workloads." },
  { domain: 3, task: "3.4", q: "What does the AWS Schema Conversion Tool (SCT) do?", opts: ["Converts database schemas from one engine to another", "Converts application code", "Migrates data between databases", "Creates database backups"], ans: 0, explain: "AWS SCT converts database schemas and code from one database engine to another, helping with heterogeneous migrations." },
  { domain: 3, task: "3.4", q: "Which of the following are benefits of managed database services? (Choose TWO)", opts: ["Automated backups and patching", "Lower-level hardware access", "Reduced operational overhead", "Full OS-level access", "Custom kernel modifications"], ans: [0, 2], multi: true, explain: "Managed databases like RDS provide automated backups, patching, and monitoring, reducing operational overhead." },
  { domain: 3, task: "3.4", q: "A gaming application needs single-digit millisecond latency for millions of reads per second. Which database is best?", opts: ["Amazon RDS MySQL", "Amazon DynamoDB", "Amazon Redshift", "Amazon Neptune"], ans: 1, explain: "DynamoDB delivers consistent single-digit millisecond latency at any scale, ideal for high-throughput gaming applications." },
  { domain: 3, task: "3.4", q: "What is an Amazon RDS Read Replica used for?", opts: ["Disaster recovery only", "Offloading read traffic from the primary database", "Writing data to multiple Regions", "Replacing the primary database"], ans: 1, explain: "RDS Read Replicas offload read traffic from the primary database to improve performance for read-heavy workloads." },
  { domain: 3, task: "3.4", q: "Which RDS feature provides high availability by maintaining a standby instance in a different AZ?", opts: ["Read Replicas", "Multi-AZ deployment", "Aurora Serverless", "Cross-Region replication"], ans: 1, explain: "RDS Multi-AZ maintains a synchronous standby replica in a different AZ for automatic failover and high availability." },
  { domain: 3, task: "3.4", q: "What is Amazon Aurora Serverless?", opts: ["A NoSQL database", "An on-demand auto-scaling configuration for Aurora", "A free tier Aurora instance", "A serverless data warehouse"], ans: 1, explain: "Aurora Serverless automatically starts, stops, and scales capacity based on application needs without managing database instances." },
  { domain: 3, task: "3.4", q: "Which ElastiCache engine supports complex data structures like sorted sets and geospatial data?", opts: ["Memcached", "Redis", "Both equally", "Neither"], ans: 1, explain: "Redis supports advanced data structures including sorted sets, geospatial data, pub/sub, and more complex operations than Memcached." },
  { domain: 3, task: "3.4", q: "A company wants to migrate from Oracle to Aurora PostgreSQL. Which tools should they use? (Choose TWO)", opts: ["AWS Schema Conversion Tool", "AWS Database Migration Service", "AWS DataSync", "AWS Transfer Family", "Amazon Kinesis"], ans: [0, 1], multi: true, explain: "SCT converts the Oracle schema to PostgreSQL format, and DMS migrates the actual data to Aurora PostgreSQL." },
  { domain: 3, task: "3.4", q: "Which database service should be used for tracking relationships between users in a social network?", opts: ["Amazon RDS", "Amazon DynamoDB", "Amazon Neptune", "Amazon Redshift"], ans: 2, explain: "Neptune is a graph database optimized for storing and querying highly connected data like social network relationships." },
  { domain: 3, task: "3.4", q: "What is the key difference between a managed database and a self-managed database on EC2?", opts: ["Managed databases are always cheaper", "With managed databases, AWS handles patching, backups, and high availability", "Self-managed databases have better performance", "Managed databases support more database engines"], ans: 1, explain: "Managed databases like RDS handle operational tasks such as patching, backups, and high availability, while self-managed databases on EC2 require you to handle these tasks." },
  { domain: 3, task: "3.4", q: "Which DynamoDB feature provides microsecond latency for read-heavy workloads?", opts: ["DynamoDB Streams", "DynamoDB Accelerator (DAX)", "DynamoDB Global Tables", "DynamoDB On-Demand"], ans: 1, explain: "DAX is an in-memory cache for DynamoDB that reduces read latency from single-digit milliseconds to microseconds." },
  { domain: 3, task: "3.4", q: "A financial services company needs to maintain an auditable history of all transactions. Which database is most appropriate?", opts: ["Amazon RDS", "Amazon QLDB", "Amazon DynamoDB", "Amazon ElastiCache"], ans: 1, explain: "QLDB provides an immutable, cryptographically verifiable transaction log, ideal for financial audit trails." },
  { domain: 3, task: "3.4", q: "Which database service is best for running OLAP (Online Analytical Processing) queries?", opts: ["Amazon DynamoDB", "Amazon RDS", "Amazon Redshift", "Amazon ElastiCache"], ans: 2, explain: "Amazon Redshift is optimized for OLAP workloads, enabling fast analytics across large datasets using columnar storage." },
  { domain: 3, task: "3.4", q: "What is DynamoDB Global Tables?", opts: ["A feature for global database administration", "Multi-Region, multi-active replication for DynamoDB", "A way to share tables between accounts", "A backup feature for DynamoDB"], ans: 1, explain: "DynamoDB Global Tables provides fully managed multi-Region, multi-active replication for global applications." },
  { domain: 3, task: "3.4", q: "Which RDS database engines does AWS manage? (Choose TWO)", opts: ["MySQL", "MongoDB", "PostgreSQL", "Cassandra", "CouchDB"], ans: [0, 2], multi: true, explain: "RDS supports MySQL, PostgreSQL, MariaDB, Oracle, SQL Server, and Aurora. MongoDB and Cassandra are NoSQL and not supported by RDS." },
  { domain: 3, task: "3.4", q: "What is the maximum storage capacity of Amazon Aurora?", opts: ["16 TB", "64 TB", "128 TB", "256 TB"], ans: 2, explain: "Amazon Aurora automatically scales storage up to 128 TB per database instance." },
  { domain: 3, task: "3.4", q: "Which service would you use to convert a SQL Server stored procedure to PostgreSQL syntax?", opts: ["AWS DMS", "AWS SCT", "AWS Glue", "AWS Lambda"], ans: 1, explain: "AWS Schema Conversion Tool converts database schema objects, including stored procedures, from one database engine to another." },
  { domain: 3, task: "3.4", q: "A company wants to use a database but only pay for actual usage with no upfront provisioning. Which option is best?", opts: ["RDS with Reserved Instances", "DynamoDB On-Demand mode", "Aurora Provisioned", "ElastiCache Reserved Nodes"], ans: 1, explain: "DynamoDB On-Demand mode charges per request with no capacity planning or upfront commitment required." },
  { domain: 3, task: "3.4", q: "What is the primary use case for Amazon Redshift Spectrum?", opts: ["Caching frequently accessed data", "Querying data in S3 without loading it into Redshift", "Real-time stream processing", "Graph database queries"], ans: 1, explain: "Redshift Spectrum allows you to run SQL queries directly against exabytes of data in S3 without loading it into Redshift tables." },
  { domain: 3, task: "3.4", q: "Which feature enables automatic failover for Amazon RDS?", opts: ["Read Replicas", "Multi-AZ deployment", "Cross-Region replication", "Parameter groups"], ans: 1, explain: "Multi-AZ deployment provides automatic failover to a standby instance in a different AZ if the primary instance fails." },
  { domain: 3, task: "3.4", q: "A company needs a database for a recommendation engine that maps relationships between products, users, and purchases. Which service is ideal?", opts: ["Amazon DynamoDB", "Amazon Neptune", "Amazon RDS", "Amazon Redshift"], ans: 1, explain: "Neptune is a graph database ideal for recommendation engines that need to traverse relationships between entities." },
  { domain: 3, task: "3.4", q: "Which DynamoDB capacity mode is best for applications with unpredictable traffic?", opts: ["Provisioned capacity", "On-demand capacity", "Reserved capacity", "Spot capacity"], ans: 1, explain: "DynamoDB On-Demand capacity mode automatically adapts to traffic patterns and charges per request, ideal for unpredictable workloads." },
  { domain: 3, task: "3.4", q: "What does AWS DMS support for continuous data replication?", opts: ["One-time migration only", "Change Data Capture (CDC) for ongoing replication", "Schema conversion only", "Backup and restore only"], ans: 1, explain: "DMS supports Change Data Capture (CDC) for continuous replication, keeping the target database synchronized with the source." },

  // ==================== TASK 3.5: Network Services (40 questions) ====================
  { domain: 3, task: "3.5", q: "What is an Amazon VPC?", opts: ["A physical data center", "A logically isolated virtual network within AWS", "A VPN connection", "A content delivery network"], ans: 1, explain: "Amazon VPC (Virtual Private Cloud) is a logically isolated virtual network that you define within AWS." },
  { domain: 3, task: "3.5", q: "What is the difference between a public subnet and a private subnet?", opts: ["Public subnets are larger than private subnets", "Public subnets have a route to an internet gateway; private subnets do not", "Private subnets cannot communicate with any other subnet", "There is no technical difference"], ans: 1, explain: "A public subnet has a route table entry pointing to an internet gateway, allowing direct internet access. Private subnets lack this route." },
  { domain: 3, task: "3.5", q: "Which component allows resources in a VPC to communicate with the internet?", opts: ["NAT Gateway", "Internet Gateway", "VPN Gateway", "Transit Gateway"], ans: 1, explain: "An Internet Gateway enables communication between resources in a VPC and the public internet." },
  { domain: 3, task: "3.5", q: "What is the purpose of a NAT Gateway?", opts: ["To provide internet access to resources in public subnets", "To allow resources in private subnets to access the internet while remaining unreachable from the internet", "To connect two VPCs together", "To provide DNS resolution"], ans: 1, explain: "A NAT Gateway enables instances in private subnets to initiate outbound internet traffic while preventing inbound connections from the internet." },
  { domain: 3, task: "3.5", q: "Which network security feature acts as a stateful firewall at the instance level?", opts: ["Network ACL", "Security Group", "AWS WAF", "AWS Shield"], ans: 1, explain: "Security Groups are stateful firewalls that control inbound and outbound traffic at the instance (ENI) level." },
  { domain: 3, task: "3.5", q: "Which network security feature acts as a stateless firewall at the subnet level?", opts: ["Security Group", "Network ACL (NACL)", "AWS WAF", "Route Table"], ans: 1, explain: "Network ACLs are stateless firewalls that control traffic at the subnet level, requiring explicit rules for both inbound and outbound traffic." },
  { domain: 3, task: "3.5", q: "What is the key difference between Security Groups and NACLs?", opts: ["Security Groups are stateful; NACLs are stateless", "NACLs are stateful; Security Groups are stateless", "Security Groups apply to subnets; NACLs apply to instances", "There is no difference"], ans: 0, explain: "Security Groups are stateful (return traffic is automatically allowed), while NACLs are stateless (return traffic must be explicitly allowed)." },
  { domain: 3, task: "3.5", q: "Which AWS service provides managed DNS?", opts: ["Amazon CloudFront", "Amazon Route 53", "AWS Direct Connect", "Amazon VPC"], ans: 1, explain: "Amazon Route 53 is a highly available and scalable DNS (Domain Name System) web service." },
  { domain: 3, task: "3.5", q: "Which service provides a dedicated private network connection from on-premises to AWS?", opts: ["AWS VPN", "AWS Direct Connect", "VPC Peering", "Internet Gateway"], ans: 1, explain: "AWS Direct Connect provides a dedicated private network connection from your on-premises data center to AWS." },
  { domain: 3, task: "3.5", q: "What is VPC Peering?", opts: ["Connecting a VPC to the internet", "A networking connection between two VPCs that enables traffic routing using private IP addresses", "Connecting a VPC to an on-premises network", "A type of load balancer"], ans: 1, explain: "VPC Peering connects two VPCs, allowing them to communicate using private IP addresses as if they were in the same network." },
  { domain: 3, task: "3.5", q: "Which service simplifies connecting multiple VPCs and on-premises networks through a central hub?", opts: ["VPC Peering", "AWS Transit Gateway", "Internet Gateway", "NAT Gateway"], ans: 1, explain: "AWS Transit Gateway acts as a central hub that connects multiple VPCs and on-premises networks through a single gateway." },
  { domain: 3, task: "3.5", q: "What is the purpose of a VPC Endpoint?", opts: ["To connect a VPC to the internet", "To privately connect a VPC to AWS services without using the internet", "To peer two VPCs", "To create a VPN tunnel"], ans: 1, explain: "VPC Endpoints enable private connectivity to AWS services from within a VPC without traversing the public internet." },
  { domain: 3, task: "3.5", q: "Which Route 53 routing policy directs traffic to the resource closest to the user?", opts: ["Simple routing", "Weighted routing", "Latency-based routing", "Failover routing"], ans: 2, explain: "Latency-based routing directs traffic to the AWS Region that provides the lowest latency for the end user." },
  { domain: 3, task: "3.5", q: "A company needs encrypted connectivity between their data center and AWS over the public internet. What should they use?", opts: ["AWS Direct Connect", "AWS Site-to-Site VPN", "VPC Peering", "Internet Gateway"], ans: 1, explain: "AWS Site-to-Site VPN creates an encrypted IPsec tunnel between the on-premises network and AWS over the public internet." },
  { domain: 3, task: "3.5", q: "Which of the following are characteristics of Security Groups? (Choose TWO)", opts: ["They support allow rules only", "They support allow and deny rules", "They are stateful", "They operate at the subnet level", "They are stateless"], ans: [0, 2], multi: true, explain: "Security Groups only support allow rules (implicit deny for everything else) and are stateful (return traffic is automatically allowed)." },
  { domain: 3, task: "3.5", q: "What is the default behavior of a Security Group for inbound traffic?", opts: ["All traffic is allowed", "All traffic is denied", "Only HTTP traffic is allowed", "Only SSH traffic is allowed"], ans: 1, explain: "By default, Security Groups deny all inbound traffic unless explicit allow rules are added." },
  { domain: 3, task: "3.5", q: "What is the default behavior of a Network ACL?", opts: ["All traffic is denied", "All traffic is allowed", "Only outbound traffic is allowed", "Only inbound traffic is allowed"], ans: 1, explain: "The default NACL allows all inbound and outbound traffic. Custom NACLs deny all traffic by default." },
  { domain: 3, task: "3.5", q: "Which Route 53 routing policy is used for active-passive failover?", opts: ["Simple routing", "Weighted routing", "Failover routing", "Geolocation routing"], ans: 2, explain: "Failover routing policy routes traffic to a primary resource and automatically fails over to a secondary resource if the primary is unhealthy." },
  { domain: 3, task: "3.5", q: "What advantage does AWS Direct Connect have over VPN?", opts: ["Lower cost", "Consistent network performance with dedicated bandwidth", "Faster to set up", "Built-in encryption"], ans: 1, explain: "Direct Connect provides consistent network performance with dedicated bandwidth, unlike VPN which traverses the variable public internet." },
  { domain: 3, task: "3.5", q: "A company has 50 VPCs that all need to communicate. What is the most scalable solution?", opts: ["50 VPC Peering connections", "AWS Transit Gateway", "50 VPN connections", "Internet Gateway for each VPC"], ans: 1, explain: "Transit Gateway provides a hub-and-spoke model, simplifying connectivity between many VPCs without creating individual peering connections." },
  { domain: 3, task: "3.5", q: "Which type of VPC Endpoint is used for S3 and DynamoDB?", opts: ["Interface endpoint", "Gateway endpoint", "PrivateLink endpoint", "Direct endpoint"], ans: 1, explain: "Gateway endpoints are used for S3 and DynamoDB, providing private access through route table entries." },
  { domain: 3, task: "3.5", q: "What is AWS PrivateLink?", opts: ["A private DNS service", "A technology for accessing services privately through interface VPC endpoints", "A type of VPN", "A direct connection to AWS"], ans: 1, explain: "AWS PrivateLink provides private connectivity to services through interface VPC endpoints, keeping traffic within the AWS network." },
  { domain: 3, task: "3.5", q: "Which Route 53 routing policy distributes traffic based on user geographic location?", opts: ["Latency-based routing", "Geolocation routing", "Simple routing", "Multivalue routing"], ans: 1, explain: "Geolocation routing directs traffic based on the geographic location of the user, useful for content localization and compliance." },
  { domain: 3, task: "3.5", q: "Which of the following are valid use cases for VPC Flow Logs? (Choose TWO)", opts: ["Monitoring network traffic", "Encrypting data in transit", "Troubleshooting connectivity issues", "Load balancing traffic", "Routing DNS queries"], ans: [0, 2], multi: true, explain: "VPC Flow Logs capture information about IP traffic going to and from network interfaces, useful for monitoring and troubleshooting." },
  { domain: 3, task: "3.5", q: "A web application in a private subnet needs to download software updates from the internet. What is needed?", opts: ["Internet Gateway only", "NAT Gateway in a public subnet", "VPC Peering", "AWS Direct Connect"], ans: 1, explain: "A NAT Gateway in a public subnet allows instances in private subnets to access the internet for outbound connections like software updates." },
  { domain: 3, task: "3.5", q: "How many internet gateways can be attached to a VPC?", opts: ["Unlimited", "One", "Two", "One per subnet"], ans: 1, explain: "Only one internet gateway can be attached to a VPC at a time." },
  { domain: 3, task: "3.5", q: "What is a limitation of VPC Peering?", opts: ["It does not support cross-Region connections", "It does not support transitive peering", "It requires Direct Connect", "It only works with public subnets"], ans: 1, explain: "VPC Peering does not support transitive peering; traffic cannot pass through one VPC to reach another peered VPC." },
  { domain: 3, task: "3.5", q: "Which Route 53 routing policy sends equal portions of traffic to multiple resources?", opts: ["Simple routing", "Weighted routing with equal weights", "Failover routing", "Geolocation routing"], ans: 1, explain: "Weighted routing with equal weights distributes traffic equally across multiple resources." },
  { domain: 3, task: "3.5", q: "A company needs to connect their AWS VPC to their on-premises network with consistent latency. Which TWO options provide this? (Choose TWO)", opts: ["AWS Direct Connect", "AWS Site-to-Site VPN over the internet", "AWS Direct Connect with VPN backup", "VPC Peering", "Internet Gateway"], ans: [0, 2], multi: true, explain: "Direct Connect provides consistent latency through dedicated connections. Direct Connect with VPN backup adds encryption and redundancy." },
  { domain: 3, task: "3.5", q: "What is a CIDR block in the context of VPC?", opts: ["A security certificate", "A range of IP addresses assigned to the VPC", "A type of firewall rule", "A routing protocol"], ans: 1, explain: "A CIDR (Classless Inter-Domain Routing) block defines the range of IP addresses available for use within a VPC." },
  { domain: 3, task: "3.5", q: "Which component determines where network traffic is directed within a VPC?", opts: ["Security Group", "Network ACL", "Route Table", "Internet Gateway"], ans: 2, explain: "Route tables contain rules (routes) that determine where network traffic from subnets or gateways is directed." },
  { domain: 3, task: "3.5", q: "A company needs DNS health checks to route traffic away from unhealthy endpoints. Which service provides this?", opts: ["Amazon CloudFront", "Amazon Route 53", "Elastic Load Balancing", "AWS WAF"], ans: 1, explain: "Route 53 health checks monitor endpoint health and can automatically route traffic away from unhealthy endpoints." },
  { domain: 3, task: "3.5", q: "What is the maximum number of VPCs per Region by default?", opts: ["1", "3", "5", "10"], ans: 2, explain: "The default limit is 5 VPCs per Region, though this can be increased by requesting a limit increase." },
  { domain: 3, task: "3.5", q: "Which service creates an encrypted tunnel over the internet between an on-premises network and an AWS VPC?", opts: ["AWS Direct Connect", "AWS Site-to-Site VPN", "VPC Peering", "Transit Gateway"], ans: 1, explain: "AWS Site-to-Site VPN creates an encrypted IPsec tunnel over the internet between on-premises infrastructure and an AWS VPC." },
  { domain: 3, task: "3.5", q: "Which feature allows you to use your own public IP address range in AWS?", opts: ["Elastic IP", "BYOIP (Bring Your Own IP)", "VPC CIDR extension", "Route 53"], ans: 1, explain: "BYOIP allows you to bring your own public IPv4 or IPv6 address range to AWS and use it with your resources." },

  // ==================== TASK 3.6: Storage Services (40 questions) ====================
  { domain: 3, task: "3.6", q: "Which S3 storage class is designed for frequently accessed data?", opts: ["S3 Standard-IA", "S3 One Zone-IA", "S3 Standard", "S3 Glacier"], ans: 2, explain: "S3 Standard is designed for frequently accessed data with high durability, availability, and performance." },
  { domain: 3, task: "3.6", q: "Which S3 storage class is best for infrequently accessed data that needs to be available across multiple AZs?", opts: ["S3 Standard", "S3 Standard-IA", "S3 One Zone-IA", "S3 Glacier"], ans: 1, explain: "S3 Standard-IA (Infrequent Access) is for infrequently accessed data that still requires high availability across multiple AZs." },
  { domain: 3, task: "3.6", q: "Which S3 storage class stores data in only one AZ at a lower cost?", opts: ["S3 Standard", "S3 Standard-IA", "S3 One Zone-IA", "S3 Glacier"], ans: 2, explain: "S3 One Zone-IA stores data in a single AZ, reducing costs compared to Standard-IA but with less availability." },
  { domain: 3, task: "3.6", q: "Which storage class provides the LOWEST cost for long-term archival storage?", opts: ["S3 Standard-IA", "S3 Glacier", "S3 Glacier Deep Archive", "S3 One Zone-IA"], ans: 2, explain: "S3 Glacier Deep Archive provides the lowest cost storage class for data that is rarely accessed and stored for 7-10 years or more." },
  { domain: 3, task: "3.6", q: "What is Amazon EBS?", opts: ["Object storage for the internet", "Block-level storage volumes for EC2 instances", "A file storage system", "A data warehouse"], ans: 1, explain: "Amazon EBS (Elastic Block Store) provides persistent block-level storage volumes for use with EC2 instances." },
  { domain: 3, task: "3.6", q: "What is Amazon EFS?", opts: ["Block storage for EC2", "A managed file system using the NFS protocol", "Object storage like S3", "A content delivery network"], ans: 1, explain: "Amazon EFS (Elastic File System) is a fully managed NFS file system that can be mounted by multiple EC2 instances simultaneously." },
  { domain: 3, task: "3.6", q: "What is a key characteristic of Amazon S3?", opts: ["It provides block-level storage", "It is an object storage service with virtually unlimited storage", "It can only store files up to 1 GB", "It requires EC2 instances to access"], ans: 1, explain: "Amazon S3 is an object storage service offering virtually unlimited storage, high durability (11 9s), and various storage classes." },
  { domain: 3, task: "3.6", q: "Which storage option is ephemeral and tied to the lifecycle of an EC2 instance?", opts: ["Amazon EBS", "Amazon S3", "Instance Store", "Amazon EFS"], ans: 2, explain: "Instance Store provides temporary block-level storage that is physically attached to the host and lost when the instance stops or terminates." },
  { domain: 3, task: "3.6", q: "Which S3 feature automatically moves objects between storage classes based on access patterns?", opts: ["S3 Versioning", "S3 Intelligent-Tiering", "S3 Lifecycle Policies", "S3 Transfer Acceleration"], ans: 1, explain: "S3 Intelligent-Tiering automatically moves objects between access tiers based on changing access patterns without performance impact." },
  { domain: 3, task: "3.6", q: "What is an S3 Lifecycle Policy used for?", opts: ["Controlling who can access objects", "Automating the transition of objects between storage classes or deletion", "Encrypting objects", "Versioning objects"], ans: 1, explain: "S3 Lifecycle Policies automate transitioning objects to different storage classes or deleting them after a specified time." },
  { domain: 3, task: "3.6", q: "What does S3 Versioning do?", opts: ["Creates copies in multiple Regions", "Keeps multiple versions of an object in the same bucket", "Compresses objects automatically", "Encrypts all objects"], ans: 1, explain: "S3 Versioning keeps multiple versions of an object in the same bucket, allowing recovery from unintended deletions or overwrites." },
  { domain: 3, task: "3.6", q: "Which service provides a hybrid cloud storage solution connecting on-premises environments with AWS cloud storage?", opts: ["AWS DataSync", "AWS Storage Gateway", "Amazon S3", "AWS Snowball"], ans: 1, explain: "AWS Storage Gateway provides hybrid cloud storage, connecting on-premises environments to AWS cloud storage services." },
  { domain: 3, task: "3.6", q: "Which service provides centralized backup management across AWS services?", opts: ["Amazon S3", "AWS Backup", "AWS Storage Gateway", "Amazon EBS Snapshots"], ans: 1, explain: "AWS Backup is a centralized service for automating and managing backups across AWS services like EBS, RDS, EFS, and DynamoDB." },
  { domain: 3, task: "3.6", q: "A company needs a Windows-compatible file system in AWS. Which service should they use?", opts: ["Amazon EFS", "Amazon FSx for Windows File Server", "Amazon S3", "Amazon EBS"], ans: 1, explain: "Amazon FSx for Windows File Server provides a fully managed Windows file system with SMB protocol support." },
  { domain: 3, task: "3.6", q: "What is the durability of Amazon S3?", opts: ["99.9%", "99.99%", "99.999999999% (11 nines)", "99.95%"], ans: 2, explain: "Amazon S3 provides 99.999999999% (11 nines) durability, meaning objects are highly unlikely to be lost." },
  { domain: 3, task: "3.6", q: "Which of the following are benefits of S3 Glacier? (Choose TWO)", opts: ["Sub-millisecond retrieval times", "Very low storage cost", "Designed for archival data", "Best for frequently accessed data", "Unlimited object size"], ans: [1, 2], multi: true, explain: "S3 Glacier provides very low storage costs and is designed for data archiving and long-term backup." },
  { domain: 3, task: "3.6", q: "What retrieval options does S3 Glacier offer? (Choose TWO)", opts: ["Instant retrieval", "Expedited (1-5 minutes)", "Standard (3-5 hours)", "Real-time", "Same-day delivery"], ans: [1, 2], multi: true, explain: "Glacier offers Expedited (1-5 minutes), Standard (3-5 hours), and Bulk (5-12 hours) retrieval options." },
  { domain: 3, task: "3.6", q: "Which EBS volume type provides the highest performance for mission-critical applications?", opts: ["General Purpose SSD (gp3)", "Provisioned IOPS SSD (io2)", "Throughput Optimized HDD (st1)", "Cold HDD (sc1)"], ans: 1, explain: "Provisioned IOPS SSD (io2) volumes deliver the highest performance with configurable IOPS for mission-critical applications." },
  { domain: 3, task: "3.6", q: "A company needs to share files between multiple EC2 instances across AZs. Which storage service is best?", opts: ["Amazon EBS", "Amazon EFS", "Instance Store", "Amazon S3"], ans: 1, explain: "Amazon EFS can be mounted by multiple EC2 instances simultaneously across multiple Availability Zones." },
  { domain: 3, task: "3.6", q: "Which storage service is best for hosting a static website?", opts: ["Amazon EBS", "Amazon EFS", "Amazon S3", "Amazon FSx"], ans: 2, explain: "Amazon S3 can host static websites directly, serving HTML, CSS, JavaScript, and other web content." },
  { domain: 3, task: "3.6", q: "What is the maximum size of a single object in Amazon S3?", opts: ["1 GB", "5 GB", "5 TB", "Unlimited"], ans: 2, explain: "The maximum size of a single S3 object is 5 TB." },
  { domain: 3, task: "3.6", q: "Which EBS volume type is most cost-effective for large, sequential workloads like data warehouses?", opts: ["General Purpose SSD (gp3)", "Provisioned IOPS SSD (io2)", "Throughput Optimized HDD (st1)", "Cold HDD (sc1)"], ans: 2, explain: "Throughput Optimized HDD (st1) is designed for large, sequential workloads at a lower cost than SSD volumes." },
  { domain: 3, task: "3.6", q: "What happens when you enable S3 Versioning and then delete an object?", opts: ["The object is permanently deleted", "A delete marker is placed, and previous versions are retained", "All versions are deleted", "The object is moved to Glacier"], ans: 1, explain: "With versioning enabled, deleting an object adds a delete marker but retains all previous versions for recovery." },
  { domain: 3, task: "3.6", q: "Which FSx file system is optimized for high-performance computing workloads?", opts: ["FSx for Windows File Server", "FSx for Lustre", "FSx for NetApp ONTAP", "FSx for OpenZFS"], ans: 1, explain: "Amazon FSx for Lustre is a high-performance file system designed for HPC, machine learning, and media processing workloads." },
  { domain: 3, task: "3.6", q: "A company wants to transition objects from S3 Standard to Glacier after 90 days automatically. What should they use?", opts: ["S3 Intelligent-Tiering", "S3 Lifecycle Policy", "S3 Replication", "S3 Transfer Acceleration"], ans: 1, explain: "S3 Lifecycle Policies can automatically transition objects to different storage classes (like Glacier) after a specified number of days." },
  { domain: 3, task: "3.6", q: "Which of the following differentiates EBS from instance store? (Choose TWO)", opts: ["EBS data persists independently of instance lifecycle", "Instance store provides higher I/O performance for temporary data", "EBS is always faster than instance store", "Instance store data persists after instance termination", "EBS cannot be resized"], ans: [0, 1], multi: true, explain: "EBS persists independently of the instance, while instance store provides high-performance temporary storage that is lost when the instance stops." },
  { domain: 3, task: "3.6", q: "What is S3 Cross-Region Replication (CRR) used for?", opts: ["Moving data between storage classes", "Automatically replicating objects to a bucket in a different Region", "Creating local copies within the same AZ", "Backing up EBS volumes"], ans: 1, explain: "S3 CRR automatically replicates objects to a destination bucket in a different AWS Region for compliance, lower latency, or disaster recovery." },
  { domain: 3, task: "3.6", q: "Which storage option provides the LOWEST cost per GB?", opts: ["EBS General Purpose SSD", "S3 Standard", "S3 Glacier Deep Archive", "Amazon EFS"], ans: 2, explain: "S3 Glacier Deep Archive provides the lowest storage cost per GB, designed for data that is rarely accessed." },
  { domain: 3, task: "3.6", q: "A company needs to store 100 TB of data that will be accessed once or twice a year for auditing. Which storage class is most cost-effective?", opts: ["S3 Standard", "S3 Standard-IA", "S3 Glacier", "S3 Glacier Deep Archive"], ans: 3, explain: "Glacier Deep Archive is the most cost-effective for data accessed very rarely (once or twice a year) and stored long-term." },
  { domain: 3, task: "3.6", q: "What is the primary advantage of S3 Intelligent-Tiering over manually setting lifecycle policies?", opts: ["It is free of charge", "It automatically optimizes costs by moving data between tiers based on actual access patterns", "It provides faster data access", "It supports larger file sizes"], ans: 1, explain: "S3 Intelligent-Tiering automatically moves data between frequent and infrequent access tiers based on actual usage, without manual configuration." },
  { domain: 3, task: "3.6", q: "Which EBS snapshot feature allows you to create point-in-time copies of volumes?", opts: ["EBS Replication", "EBS Snapshots", "EBS Mirroring", "EBS Backup"], ans: 1, explain: "EBS Snapshots create point-in-time copies of EBS volumes, stored in S3, that can be used to restore or create new volumes." },
  { domain: 3, task: "3.6", q: "How does EBS differ from S3?", opts: ["EBS is object storage; S3 is block storage", "EBS provides block storage for EC2; S3 provides object storage accessible via HTTP", "EBS is cheaper than S3", "S3 requires EC2 to access data"], ans: 1, explain: "EBS provides block-level storage attached to EC2 instances, while S3 provides object storage accessible over HTTP/HTTPS." },
  { domain: 3, task: "3.6", q: "Which AWS service would you use to transfer large amounts of data using physical devices?", opts: ["AWS DataSync", "AWS Snowball", "AWS Storage Gateway", "S3 Transfer Acceleration"], ans: 1, explain: "AWS Snowball uses physical devices to transfer large amounts of data to and from AWS when network transfer is too slow or costly." },
  { domain: 3, task: "3.6", q: "What is the retrieval time for S3 Glacier Deep Archive standard retrieval?", opts: ["Minutes", "1-5 hours", "Within 12 hours", "24-48 hours"], ans: 2, explain: "S3 Glacier Deep Archive standard retrieval takes within 12 hours, with bulk retrieval taking up to 48 hours." },
  { domain: 3, task: "3.6", q: "A company wants to protect against accidental deletion of S3 objects. Which TWO features help? (Choose TWO)", opts: ["S3 Versioning", "S3 MFA Delete", "S3 Transfer Acceleration", "S3 Intelligent-Tiering", "S3 Lifecycle Policies"], ans: [0, 1], multi: true, explain: "S3 Versioning preserves previous versions of objects, and MFA Delete requires MFA authentication to permanently delete versioned objects." },

  // ==================== TASK 3.7: AI/ML and Analytics (45 questions) ====================
  { domain: 3, task: "3.7", q: "Which AWS service is a fully managed platform for building, training, and deploying machine learning models?", opts: ["Amazon Rekognition", "Amazon SageMaker", "Amazon Comprehend", "AWS Glue"], ans: 1, explain: "Amazon SageMaker is a fully managed service for the complete ML workflow: building, training, and deploying models." },
  { domain: 3, task: "3.7", q: "Which service analyzes images and videos to detect objects, people, and activities?", opts: ["Amazon Comprehend", "Amazon Rekognition", "Amazon Textract", "Amazon Polly"], ans: 1, explain: "Amazon Rekognition uses deep learning to analyze images and videos for object detection, facial analysis, and content moderation." },
  { domain: 3, task: "3.7", q: "Which service converts text to lifelike speech?", opts: ["Amazon Lex", "Amazon Transcribe", "Amazon Polly", "Amazon Translate"], ans: 2, explain: "Amazon Polly converts text into lifelike speech, supporting multiple languages and voices." },
  { domain: 3, task: "3.7", q: "Which service is used to build conversational chatbots?", opts: ["Amazon Polly", "Amazon Lex", "Amazon Comprehend", "Amazon Kendra"], ans: 1, explain: "Amazon Lex provides conversational AI capabilities for building chatbots with natural language understanding and speech recognition." },
  { domain: 3, task: "3.7", q: "Which service extracts text, forms, and tables from scanned documents?", opts: ["Amazon Rekognition", "Amazon Textract", "Amazon Comprehend", "Amazon Translate"], ans: 1, explain: "Amazon Textract uses ML to extract text, handwriting, forms, and tables from scanned documents automatically." },
  { domain: 3, task: "3.7", q: "Which service provides natural language processing to find insights and relationships in text?", opts: ["Amazon Textract", "Amazon Lex", "Amazon Comprehend", "Amazon Translate"], ans: 2, explain: "Amazon Comprehend uses NLP to discover insights like sentiment, key phrases, entities, and language in text." },
  { domain: 3, task: "3.7", q: "Which service translates text between languages?", opts: ["Amazon Polly", "Amazon Transcribe", "Amazon Translate", "Amazon Comprehend"], ans: 2, explain: "Amazon Translate provides neural machine translation for translating text between supported languages." },
  { domain: 3, task: "3.7", q: "Which service provides intelligent search powered by machine learning?", opts: ["Amazon Elasticsearch", "Amazon Kendra", "Amazon CloudSearch", "Amazon Athena"], ans: 1, explain: "Amazon Kendra is an ML-powered enterprise search service that provides natural language search capabilities." },
  { domain: 3, task: "3.7", q: "Which service provides real-time personalization and recommendations?", opts: ["Amazon Comprehend", "Amazon Personalize", "Amazon Forecast", "Amazon SageMaker"], ans: 1, explain: "Amazon Personalize creates individualized recommendations for customers, similar to the technology used by Amazon.com." },
  { domain: 3, task: "3.7", q: "Which service allows you to run SQL queries directly on data stored in S3?", opts: ["Amazon RDS", "Amazon Athena", "Amazon Redshift", "AWS Glue"], ans: 1, explain: "Amazon Athena is a serverless query service that allows you to analyze data in S3 using standard SQL." },
  { domain: 3, task: "3.7", q: "Which service processes real-time streaming data?", opts: ["Amazon Athena", "Amazon Kinesis", "Amazon EMR", "AWS Glue"], ans: 1, explain: "Amazon Kinesis collects, processes, and analyzes real-time streaming data at any scale." },
  { domain: 3, task: "3.7", q: "What is AWS Glue used for?", opts: ["Machine learning model training", "Serverless data integration and ETL (extract, transform, load)", "Real-time data streaming", "Business intelligence dashboards"], ans: 1, explain: "AWS Glue is a serverless data integration service for ETL, preparing and combining data for analytics and ML." },
  { domain: 3, task: "3.7", q: "Which service provides business intelligence dashboards and visualizations?", opts: ["Amazon Athena", "Amazon QuickSight", "AWS Glue", "Amazon Kinesis"], ans: 1, explain: "Amazon QuickSight is a serverless BI service that creates interactive dashboards and visualizations." },
  { domain: 3, task: "3.7", q: "What is Amazon EMR used for?", opts: ["Email marketing", "Big data processing using frameworks like Apache Spark and Hadoop", "Container orchestration", "Database migration"], ans: 1, explain: "Amazon EMR (Elastic MapReduce) is a managed big data platform for processing large datasets using frameworks like Spark, Hadoop, and Hive." },
  { domain: 3, task: "3.7", q: "Which of the following are AWS AI services that require NO ML expertise? (Choose TWO)", opts: ["Amazon SageMaker", "Amazon Rekognition", "Amazon Polly", "AWS Deep Learning AMIs", "Amazon SageMaker Ground Truth"], ans: [1, 2], multi: true, explain: "Rekognition and Polly are pre-built AI services that require no ML expertise, unlike SageMaker which is for building custom ML models." },
  { domain: 3, task: "3.7", q: "A company needs to analyze customer reviews to determine sentiment (positive/negative). Which service should they use?", opts: ["Amazon Lex", "Amazon Comprehend", "Amazon Polly", "Amazon Textract"], ans: 1, explain: "Amazon Comprehend provides sentiment analysis as one of its NLP capabilities, determining if text is positive, negative, neutral, or mixed." },
  { domain: 3, task: "3.7", q: "Which Kinesis service captures and stores streaming video data?", opts: ["Kinesis Data Streams", "Kinesis Data Firehose", "Kinesis Video Streams", "Kinesis Data Analytics"], ans: 2, explain: "Kinesis Video Streams captures, processes, and stores streaming video from connected devices." },
  { domain: 3, task: "3.7", q: "Which service delivers real-time streaming data to destinations like S3, Redshift, or Elasticsearch?", opts: ["Kinesis Data Streams", "Kinesis Data Firehose", "Kinesis Video Streams", "Amazon SQS"], ans: 1, explain: "Kinesis Data Firehose is the easiest way to load streaming data into AWS data stores and analytics services." },
  { domain: 3, task: "3.7", q: "A company needs to process millions of invoice images to extract line items and totals. Which service is best?", opts: ["Amazon Rekognition", "Amazon Textract", "Amazon Comprehend", "Amazon Translate"], ans: 1, explain: "Textract specializes in extracting text, forms, and tables from documents including invoices." },
  { domain: 3, task: "3.7", q: "Which service provides a data catalog to discover and manage metadata about data stores?", opts: ["Amazon Athena", "AWS Glue Data Catalog", "Amazon Redshift", "Amazon QuickSight"], ans: 1, explain: "AWS Glue Data Catalog is a centralized metadata repository that stores structural and operational metadata about data assets." },
  { domain: 3, task: "3.7", q: "A company wants to build a voice-controlled assistant for their mobile app. Which services should they use? (Choose TWO)", opts: ["Amazon Lex", "Amazon Polly", "Amazon Rekognition", "Amazon Textract", "Amazon Translate"], ans: [0, 1], multi: true, explain: "Lex provides speech recognition and conversational AI, while Polly converts response text to speech for the voice assistant." },
  { domain: 3, task: "3.7", q: "Which analytics service is serverless and charges per query based on the amount of data scanned?", opts: ["Amazon EMR", "Amazon Athena", "Amazon Redshift", "AWS Glue"], ans: 1, explain: "Athena is serverless and charges based on the amount of data scanned per query, with no infrastructure to manage." },
  { domain: 3, task: "3.7", q: "What is the primary difference between Athena and Redshift?", opts: ["Athena is for real-time queries; Redshift is for batch", "Athena is serverless for ad-hoc queries on S3; Redshift is a provisioned data warehouse", "Redshift is free; Athena is paid", "Athena supports SQL; Redshift does not"], ans: 1, explain: "Athena is serverless for ad-hoc queries directly on S3 data, while Redshift is a fully managed data warehouse for complex analytics." },
  { domain: 3, task: "3.7", q: "Which service would help a media company automatically detect inappropriate content in uploaded videos?", opts: ["Amazon Polly", "Amazon Rekognition", "Amazon Comprehend", "Amazon Lex"], ans: 1, explain: "Rekognition provides content moderation capabilities to detect inappropriate or unsafe content in images and videos." },
  { domain: 3, task: "3.7", q: "A data engineering team needs to run Apache Spark jobs on large datasets. Which service should they use?", opts: ["Amazon Athena", "Amazon EMR", "AWS Lambda", "Amazon Kinesis"], ans: 1, explain: "Amazon EMR provides a managed platform for running Apache Spark, Hadoop, and other big data frameworks." },
  { domain: 3, task: "3.7", q: "Which service provides an AI-powered assistant for answering questions about AWS and business data?", opts: ["Amazon Kendra", "Amazon Q", "Amazon Comprehend", "Amazon Lex"], ans: 1, explain: "Amazon Q is a generative AI-powered assistant that can answer questions, generate content, and take actions based on enterprise data." },
  { domain: 3, task: "3.7", q: "What type of data does Kinesis Data Analytics process?", opts: ["Static files in S3", "Streaming data in real time using SQL or Apache Flink", "Database queries", "Email messages"], ans: 1, explain: "Kinesis Data Analytics processes and analyzes streaming data in real time using SQL or Apache Flink." },
  { domain: 3, task: "3.7", q: "Which AWS service would you use to create an ML model for fraud detection with your own training data?", opts: ["Amazon Rekognition", "Amazon Comprehend", "Amazon SageMaker", "Amazon Personalize"], ans: 2, explain: "SageMaker provides the tools to build, train, and deploy custom ML models using your own data for use cases like fraud detection." },
  { domain: 3, task: "3.7", q: "Which of the following are components of Amazon Kinesis? (Choose TWO)", opts: ["Kinesis Data Streams", "Kinesis Data Lakes", "Kinesis Data Firehose", "Kinesis Data Tables", "Kinesis Data Blocks"], ans: [0, 2], multi: true, explain: "Kinesis includes Data Streams (custom processing), Data Firehose (delivery), Video Streams, and Data Analytics." },
  { domain: 3, task: "3.7", q: "A healthcare company needs to extract information from patient forms and medical records. Which service is most appropriate?", opts: ["Amazon Comprehend Medical", "Amazon Textract", "Amazon Translate", "Amazon Polly"], ans: 0, explain: "Amazon Comprehend Medical uses NLP to extract medical information from unstructured medical text." },
  { domain: 3, task: "3.7", q: "Which service converts speech to text?", opts: ["Amazon Polly", "Amazon Transcribe", "Amazon Lex", "Amazon Comprehend"], ans: 1, explain: "Amazon Transcribe is an automatic speech recognition service that converts speech to text." },
  { domain: 3, task: "3.7", q: "A retail company wants to provide product recommendations based on customer browsing and purchase history. Which service is best?", opts: ["Amazon Comprehend", "Amazon Kendra", "Amazon Personalize", "Amazon SageMaker"], ans: 2, explain: "Amazon Personalize provides real-time personalized recommendations based on user behavior data, similar to Amazon.com's recommendation engine." },
  { domain: 3, task: "3.7", q: "Which service is best for creating interactive dashboards that can be embedded in applications?", opts: ["Amazon Athena", "Amazon QuickSight", "AWS Glue", "Amazon CloudWatch"], ans: 1, explain: "QuickSight provides interactive dashboards that can be embedded in applications, websites, and portals." },
  { domain: 3, task: "3.7", q: "What does Amazon Forecast do?", opts: ["Predicts the weather", "Uses ML to deliver accurate time-series forecasting", "Forecasts AWS costs", "Predicts infrastructure failures"], ans: 1, explain: "Amazon Forecast uses ML to deliver highly accurate time-series forecasts for business metrics like demand, revenue, and inventory." },
  { domain: 3, task: "3.7", q: "Which analytics service is used for running SQL queries on data in S3 without loading it into a database?", opts: ["Amazon RDS", "Amazon Redshift", "Amazon Athena", "AWS Glue"], ans: 2, explain: "Athena queries data directly in S3 using standard SQL without requiring data to be loaded into a separate database." },
  { domain: 3, task: "3.7", q: "A company needs to detect faces in images for an identity verification system. Which service should they use?", opts: ["Amazon Comprehend", "Amazon Rekognition", "Amazon Textract", "Amazon Personalize"], ans: 1, explain: "Amazon Rekognition provides facial detection, analysis, and comparison capabilities for identity verification." },
  { domain: 3, task: "3.7", q: "Which service would you use to automatically translate a website into multiple languages?", opts: ["Amazon Comprehend", "Amazon Polly", "Amazon Translate", "Amazon Lex"], ans: 2, explain: "Amazon Translate provides neural machine translation for translating content between languages." },
  { domain: 3, task: "3.7", q: "What is the primary purpose of SageMaker Studio?", opts: ["Deploying web applications", "An integrated development environment for ML", "Managing databases", "Monitoring infrastructure"], ans: 1, explain: "SageMaker Studio is a web-based IDE for machine learning that provides tools for building, training, debugging, deploying, and monitoring ML models." },
  { domain: 3, task: "3.7", q: "Which combination of services creates an end-to-end data analytics pipeline? (Choose TWO)", opts: ["AWS Glue for ETL", "Amazon QuickSight for visualization", "Amazon Lex for chatbots", "Amazon Polly for speech", "AWS IAM for identity"], ans: [0, 1], multi: true, explain: "Glue performs ETL to prepare data, and QuickSight creates visualizations and dashboards, forming key parts of an analytics pipeline." },
  { domain: 3, task: "3.7", q: "A news organization needs to automatically categorize articles by topic. Which service helps?", opts: ["Amazon Textract", "Amazon Comprehend", "Amazon Lex", "Amazon Rekognition"], ans: 1, explain: "Amazon Comprehend uses NLP to identify topics and classify text documents into categories." },
  { domain: 3, task: "3.7", q: "Which AWS service helps discover, prepare, and combine data for analytics and ML?", opts: ["Amazon Athena", "AWS Glue", "Amazon EMR", "Amazon Kinesis"], ans: 1, explain: "AWS Glue provides data discovery, preparation, and integration capabilities for analytics and machine learning workloads." },
  { domain: 3, task: "3.7", q: "A company wants to analyze click-stream data from their website in real time. Which service should they use?", opts: ["Amazon Athena", "Amazon Kinesis", "AWS Glue", "Amazon EMR"], ans: 1, explain: "Amazon Kinesis is designed for real-time streaming data ingestion and analysis, ideal for click-stream data." },
  { domain: 3, task: "3.7", q: "Which AWS service uses generative AI to help developers write, debug, and transform code?", opts: ["Amazon CodeWhisperer", "Amazon Q Developer", "Amazon SageMaker", "AWS CodeBuild"], ans: 1, explain: "Amazon Q Developer (formerly CodeWhisperer) is an AI-powered coding assistant that helps with code generation, debugging, and transformation." },
  { domain: 3, task: "3.7", q: "What is the primary benefit of using Athena with data stored in S3?", opts: ["It provides real-time streaming analytics", "It allows ad-hoc SQL queries without provisioning infrastructure", "It automatically creates visualizations", "It replaces the need for ETL"], ans: 1, explain: "Athena enables ad-hoc SQL queries on S3 data without any infrastructure provisioning, paying only for data scanned." },

  // ==================== TASK 3.8: Other Services (45 questions) ====================
  { domain: 3, task: "3.8", q: "Which service provides a fully managed pub/sub messaging service for application-to-application and application-to-person messaging?", opts: ["Amazon SQS", "Amazon SNS", "Amazon EventBridge", "AWS Step Functions"], ans: 1, explain: "Amazon SNS (Simple Notification Service) is a pub/sub messaging service for sending messages to multiple subscribers." },
  { domain: 3, task: "3.8", q: "Which service provides a fully managed message queue for decoupling application components?", opts: ["Amazon SNS", "Amazon SQS", "Amazon Kinesis", "AWS Step Functions"], ans: 1, explain: "Amazon SQS (Simple Queue Service) provides a fully managed message queue for decoupling and scaling distributed systems." },
  { domain: 3, task: "3.8", q: "What is the key difference between Amazon SNS and Amazon SQS?", opts: ["SNS is cheaper than SQS", "SNS pushes messages to subscribers; SQS stores messages for consumers to poll", "SQS supports email notifications; SNS does not", "They are the same service"], ans: 1, explain: "SNS pushes messages to multiple subscribers (pub/sub), while SQS stores messages in a queue for consumers to poll and process." },
  { domain: 3, task: "3.8", q: "Which service is a serverless event bus for connecting application components using events?", opts: ["Amazon SQS", "Amazon SNS", "Amazon EventBridge", "AWS Step Functions"], ans: 2, explain: "Amazon EventBridge is a serverless event bus that connects applications using events from AWS services, SaaS apps, and custom sources." },
  { domain: 3, task: "3.8", q: "Which service orchestrates multiple AWS services into serverless workflows?", opts: ["Amazon EventBridge", "AWS Step Functions", "Amazon SQS", "AWS Lambda"], ans: 1, explain: "AWS Step Functions coordinates multiple AWS services into serverless workflows with visual state machines." },
  { domain: 3, task: "3.8", q: "Which service provides a cloud-based contact center?", opts: ["Amazon SES", "Amazon Connect", "Amazon SNS", "Amazon Chime"], ans: 1, explain: "Amazon Connect is a cloud-based contact center service that provides an easy-to-use omnichannel cloud contact center." },
  { domain: 3, task: "3.8", q: "Which service is used for sending bulk emails?", opts: ["Amazon SNS", "Amazon SES", "Amazon Connect", "Amazon Pinpoint"], ans: 1, explain: "Amazon SES (Simple Email Service) is a cost-effective email service for sending transactional and bulk emails." },
  { domain: 3, task: "3.8", q: "Which service provides virtual desktops in the cloud?", opts: ["Amazon AppStream 2.0", "Amazon WorkSpaces", "AWS Cloud9", "Amazon Lightsail"], ans: 1, explain: "Amazon WorkSpaces provides fully managed, persistent cloud-based virtual desktops (Desktop as a Service)." },
  { domain: 3, task: "3.8", q: "What is Amazon AppStream 2.0 used for?", opts: ["Streaming video content", "Streaming desktop applications to users through a web browser", "Processing data streams", "Building mobile apps"], ans: 1, explain: "AppStream 2.0 streams desktop applications to users through a web browser without installing them locally." },
  { domain: 3, task: "3.8", q: "Which service helps developers build full-stack web and mobile applications?", opts: ["AWS Amplify", "AWS AppSync", "AWS CodeBuild", "Amazon Lightsail"], ans: 0, explain: "AWS Amplify provides tools and services for building full-stack web and mobile applications with features like hosting, authentication, and APIs." },
  { domain: 3, task: "3.8", q: "What is AWS AppSync used for?", opts: ["Synchronizing files between devices", "Creating managed GraphQL and Pub/Sub APIs", "Syncing data between databases", "Application deployment"], ans: 1, explain: "AWS AppSync creates managed GraphQL and Pub/Sub APIs that connect applications to data sources." },
  { domain: 3, task: "3.8", q: "Which service connects IoT devices to the AWS cloud?", opts: ["Amazon Connect", "AWS IoT Core", "Amazon Kinesis", "AWS Direct Connect"], ans: 1, explain: "AWS IoT Core connects IoT devices to the cloud, enabling secure communication and data processing from connected devices." },
  { domain: 3, task: "3.8", q: "Which service compiles source code, runs tests, and produces deployable artifacts?", opts: ["AWS CodeCommit", "AWS CodeBuild", "AWS CodeDeploy", "AWS CodePipeline"], ans: 1, explain: "AWS CodeBuild is a fully managed build service that compiles source code, runs tests, and produces software packages." },
  { domain: 3, task: "3.8", q: "Which service automates continuous delivery pipelines?", opts: ["AWS CodeBuild", "AWS CodeDeploy", "AWS CodePipeline", "AWS CodeCommit"], ans: 2, explain: "AWS CodePipeline is a continuous delivery service that automates release pipelines for fast and reliable updates." },
  { domain: 3, task: "3.8", q: "Which service automates application deployments to EC2 instances, Lambda, and ECS?", opts: ["AWS CodeBuild", "AWS CodeDeploy", "AWS CodePipeline", "AWS CodeCommit"], ans: 1, explain: "AWS CodeDeploy automates application deployments to various compute services including EC2, Lambda, and ECS." },
  { domain: 3, task: "3.8", q: "Which service provides a managed Git-based source code repository?", opts: ["AWS CodeBuild", "AWS CodeDeploy", "AWS CodePipeline", "AWS CodeCommit"], ans: 3, explain: "AWS CodeCommit is a fully managed source control service that hosts secure Git-based repositories." },
  { domain: 3, task: "3.8", q: "Which service helps analyze and debug distributed applications?", opts: ["Amazon CloudWatch", "AWS X-Ray", "AWS CloudTrail", "AWS Config"], ans: 1, explain: "AWS X-Ray helps analyze and debug distributed applications by providing end-to-end tracing of requests." },
  { domain: 3, task: "3.8", q: "Which service provides monitoring, logging, and alerting for AWS resources?", opts: ["AWS X-Ray", "Amazon CloudWatch", "AWS CloudTrail", "AWS Config"], ans: 1, explain: "Amazon CloudWatch monitors AWS resources and applications, collecting metrics, logs, and providing alarms." },
  { domain: 3, task: "3.8", q: "What is AWS Systems Manager used for?", opts: ["Managing IAM policies", "Providing operational visibility and control of AWS resources", "Building machine learning models", "Managing DNS records"], ans: 1, explain: "AWS Systems Manager provides a unified interface for managing AWS resources, automating operational tasks, and maintaining compliance." },
  { domain: 3, task: "3.8", q: "Which of the following are features of Amazon CloudWatch? (Choose TWO)", opts: ["Metrics monitoring", "Source code management", "Alarms and notifications", "Code compilation", "Schema conversion"], ans: [0, 2], multi: true, explain: "CloudWatch provides metrics monitoring for AWS resources and alarms that trigger notifications based on metric thresholds." },
  { domain: 3, task: "3.8", q: "A company needs to automate patching of EC2 instances across their fleet. Which service should they use?", opts: ["AWS CodeDeploy", "AWS Systems Manager Patch Manager", "Amazon Inspector", "AWS Config"], ans: 1, explain: "Systems Manager Patch Manager automates the process of patching managed instances with security-related and other updates." },
  { domain: 3, task: "3.8", q: "Which service would you use to trace a request as it passes through multiple microservices?", opts: ["Amazon CloudWatch", "AWS X-Ray", "AWS CloudTrail", "Amazon EventBridge"], ans: 1, explain: "X-Ray provides end-to-end request tracing across microservices, helping identify performance bottlenecks and errors." },
  { domain: 3, task: "3.8", q: "What is the difference between Amazon SQS Standard and FIFO queues?", opts: ["Standard queues are faster; FIFO queues have limited throughput but guarantee order and exactly-once processing", "FIFO queues are cheaper", "Standard queues only work in one Region", "There is no difference"], ans: 0, explain: "Standard queues offer higher throughput with best-effort ordering, while FIFO queues guarantee message order and exactly-once processing." },
  { domain: 3, task: "3.8", q: "Which AWS service can be used to create event-driven architectures responding to changes in AWS resources?", opts: ["AWS Step Functions", "Amazon EventBridge", "Amazon SQS", "AWS CodePipeline"], ans: 1, explain: "EventBridge receives events from AWS services and routes them to targets, enabling event-driven architectures." },
  { domain: 3, task: "3.8", q: "A company wants to build a CI/CD pipeline. Which combination of services should they use? (Choose TWO)", opts: ["AWS CodePipeline", "Amazon Connect", "AWS CodeBuild", "Amazon WorkSpaces", "Amazon SES"], ans: [0, 2], multi: true, explain: "CodePipeline orchestrates the CI/CD workflow, and CodeBuild handles the build and test phases." },
  { domain: 3, task: "3.8", q: "Which service provides a visual workflow for coordinating Lambda functions and other AWS services?", opts: ["Amazon EventBridge", "AWS Step Functions", "AWS CodePipeline", "Amazon SQS"], ans: 1, explain: "Step Functions provides visual workflows (state machines) to coordinate Lambda functions and other services." },
  { domain: 3, task: "3.8", q: "What is CloudWatch Logs used for?", opts: ["Tracking API calls", "Centralizing and monitoring log data from applications and AWS services", "Managing source code", "Building ML models"], ans: 1, explain: "CloudWatch Logs centralizes log data from AWS services and applications for monitoring, searching, and analysis." },
  { domain: 3, task: "3.8", q: "Which Systems Manager feature allows you to remotely run commands on EC2 instances without SSH?", opts: ["Patch Manager", "Run Command", "Parameter Store", "Session Manager"], ans: 1, explain: "Systems Manager Run Command lets you remotely execute commands on managed instances without needing SSH or RDP access." },
  { domain: 3, task: "3.8", q: "Which service stores configuration data, secrets, and parameters centrally?", opts: ["AWS Secrets Manager", "Systems Manager Parameter Store", "Amazon S3", "AWS Config"], ans: 1, explain: "Systems Manager Parameter Store provides centralized storage for configuration data, strings, and secrets." },
  { domain: 3, task: "3.8", q: "A company needs to send push notifications to millions of mobile devices. Which service should they use?", opts: ["Amazon SES", "Amazon SNS", "Amazon SQS", "Amazon Connect"], ans: 1, explain: "Amazon SNS supports mobile push notifications to millions of devices across platforms like iOS, Android, and Fire OS." },
  { domain: 3, task: "3.8", q: "Which of the following are deployment strategies supported by AWS CodeDeploy? (Choose TWO)", opts: ["Blue/green deployment", "Canary deployment", "Waterfall deployment", "Spiral deployment", "V-model deployment"], ans: [0, 1], multi: true, explain: "CodeDeploy supports blue/green, canary, and in-place (rolling) deployment strategies." },
  { domain: 3, task: "3.8", q: "What does Amazon EventBridge allow you to do with events from SaaS applications?", opts: ["Block all SaaS events", "Receive and route events from SaaS partners to AWS services", "Convert SaaS data to SQL", "Replicate SaaS databases"], ans: 1, explain: "EventBridge integrates with SaaS partners, allowing you to receive events from third-party applications and route them to AWS targets." },
  { domain: 3, task: "3.8", q: "Which service provides secure, browser-based access to EC2 instances without opening inbound ports?", opts: ["AWS Systems Manager Session Manager", "AWS CloudShell", "Amazon WorkSpaces", "AWS VPN"], ans: 0, explain: "Systems Manager Session Manager provides browser-based shell access to instances without needing SSH keys or opening inbound ports." },
  { domain: 3, task: "3.8", q: "A company wants to monitor CPU utilization and set an alarm when it exceeds 80%. Which service should they use?", opts: ["AWS X-Ray", "Amazon CloudWatch", "AWS CloudTrail", "AWS Config"], ans: 1, explain: "CloudWatch monitors metrics like CPU utilization and can trigger alarms when thresholds are exceeded." },
  { domain: 3, task: "3.8", q: "Which service provides a managed workflow for building, testing, and deploying code changes?", opts: ["AWS CodeCommit", "AWS CodePipeline", "AWS CodeBuild", "AWS CodeDeploy"], ans: 1, explain: "CodePipeline orchestrates the entire software release workflow including source, build, test, and deploy stages." },
  { domain: 3, task: "3.8", q: "What is the purpose of CloudWatch dashboards?", opts: ["To manage IAM users", "To create customizable visualizations of metrics and alarms", "To deploy applications", "To manage databases"], ans: 1, explain: "CloudWatch dashboards provide customizable views of metrics and alarms for monitoring the health of AWS resources." },
  { domain: 3, task: "3.8", q: "Which service should a company use to decouple a web tier from a processing tier?", opts: ["Amazon SNS", "Amazon SQS", "AWS Step Functions", "Amazon EventBridge"], ans: 1, explain: "SQS acts as a buffer between tiers, allowing the web tier to send messages that the processing tier consumes at its own pace." },
  { domain: 3, task: "3.8", q: "A company needs to stream desktop applications to contractors without providing full virtual desktops. Which service is best?", opts: ["Amazon WorkSpaces", "Amazon AppStream 2.0", "AWS Cloud9", "Amazon EC2"], ans: 1, explain: "AppStream 2.0 streams individual applications (not full desktops) to users through a web browser." },
  { domain: 3, task: "3.8", q: "Which feature of AWS Step Functions ensures a workflow step is retried automatically on failure?", opts: ["Error handling with retry and catch", "Dead letter queue", "Message deduplication", "Event replay"], ans: 0, explain: "Step Functions supports built-in error handling with Retry (automatic retries) and Catch (fallback states) for workflow steps." },
  { domain: 3, task: "3.8", q: "Which CloudWatch feature can trigger automated actions based on metric conditions?", opts: ["CloudWatch Logs", "CloudWatch Alarms", "CloudWatch Events", "CloudWatch Dashboards"], ans: 1, explain: "CloudWatch Alarms watch metrics and trigger automated actions (like Auto Scaling or SNS notifications) when thresholds are breached." },
  { domain: 3, task: "3.8", q: "A company wants to run commands on hundreds of EC2 instances simultaneously without SSH. Which tool should they use?", opts: ["AWS CodeDeploy", "Systems Manager Run Command", "AWS CloudFormation", "AWS Lambda"], ans: 1, explain: "Systems Manager Run Command can execute commands on multiple instances simultaneously without SSH access." },
  { domain: 3, task: "3.8", q: "Which of the following can CloudWatch monitor? (Choose TWO)", opts: ["EC2 instance CPU utilization", "RDS database connections", "Git commit history", "IAM policy changes", "S3 bucket names"], ans: [0, 1], multi: true, explain: "CloudWatch monitors operational metrics from AWS services including EC2 CPU utilization and RDS database connections." },
  { domain: 3, task: "3.8", q: "What is the primary purpose of AWS X-Ray service maps?", opts: ["Displaying geographic locations of users", "Visualizing the components of a distributed application and their interactions", "Mapping VPC network topology", "Showing S3 bucket structures"], ans: 1, explain: "X-Ray service maps provide a visual representation of distributed application components and the connections between them." },
  { domain: 3, task: "3.8", q: "Which messaging pattern does Amazon SNS implement?", opts: ["Point-to-point", "Publish/Subscribe (fan-out)", "Request/Response", "Streaming"], ans: 1, explain: "SNS implements the publish/subscribe pattern, where a message published to a topic is delivered to all subscribers (fan-out)." },
  { domain: 3, task: "3.8", q: "A developer needs to store database connection strings securely and rotate them automatically. Which service is best?", opts: ["Systems Manager Parameter Store", "AWS Secrets Manager", "Amazon S3", "AWS KMS"], ans: 1, explain: "AWS Secrets Manager stores, retrieves, and automatically rotates database credentials and other secrets." },

  // ==================== Additional Multi-Answer Questions (Tasks 3.1–3.6) ====================
  { domain: 3, task: "3.1", q: "A company is evaluating IaC tools on AWS. Which of the following are valid IaC approaches for provisioning AWS resources? (Select TWO)", opts: ["AWS CloudFormation with YAML templates", "AWS CDK with TypeScript", "Amazon CloudWatch with dashboards", "AWS Trusted Advisor recommendations", "Amazon Inspector scans"], ans: [0, 1], multi: true, explain: "CloudFormation uses YAML/JSON templates and CDK uses programming languages like TypeScript to define infrastructure as code. The other options are monitoring, advisory, and security services, not IaC tools." },
  { domain: 3, task: "3.1", q: "A solutions architect wants to preview infrastructure changes before applying them and also deploy identical stacks across multiple AWS accounts. Which CloudFormation features support these goals? (Select TWO)", opts: ["CloudFormation Change Sets", "CloudFormation StackSets", "CloudFormation Drift Detection", "CloudFormation Designer", "CloudFormation Nested Stacks"], ans: [0, 1], multi: true, explain: "Change Sets let you preview proposed changes before executing them. StackSets enable deployment of stacks across multiple accounts and Regions. Drift Detection checks for out-of-band changes, Designer is a visual editor, and Nested Stacks organize complex templates." },
  { domain: 3, task: "3.2", q: "A company is designing a disaster recovery strategy that balances cost and recovery speed. Which TWO strategies provide a running environment in a secondary Region that can quickly scale to full production capacity? (Select TWO)", opts: ["Backup and restore", "Pilot light", "Warm standby", "Multi-site active-active", "Single-AZ deployment"], ans: [1, 2], multi: true, explain: "Pilot light keeps core components (like databases) running in a secondary Region, while warm standby runs a scaled-down but functional copy. Both can scale to full capacity during failover. Backup and restore has no running environment, and multi-site active-active already runs at full capacity." },
  { domain: 3, task: "3.2", q: "Which of the following are types of AWS edge infrastructure that extend services beyond standard Regions? (Select TWO)", opts: ["AWS Local Zones", "AWS Wavelength Zones", "Availability Zones", "AWS GovCloud Regions", "Reserved Instances"], ans: [0, 1], multi: true, explain: "Local Zones extend Regions closer to population centers for low-latency use cases, and Wavelength Zones embed compute at the edge of 5G networks. Availability Zones are within Regions, GovCloud is a separate Region type, and Reserved Instances are a pricing model." },
  { domain: 3, task: "3.2", q: "A multinational company must comply with data residency laws in Europe and also serve users in Asia with low latency. Which TWO actions should they take? (Select TWO)", opts: ["Store regulated data in an EU Region to meet compliance requirements", "Deploy application resources in an Asia Pacific Region for low-latency access", "Use a single US Region for all workloads to simplify management", "Disable CloudFront to prevent data from being cached outside the EU", "Use AWS GovCloud for all international traffic"], ans: [0, 1], multi: true, explain: "Choosing an EU Region ensures data residency compliance, while deploying in an Asia Pacific Region reduces latency for Asian users. A single US Region would violate EU data residency rules. CloudFront can be configured with geographic restrictions if needed rather than disabled entirely." },
  { domain: 3, task: "3.3", q: "A company is containerizing its microservices and evaluating orchestration options. Which of the following are container orchestration or compute services for running containers on AWS? (Select THREE)", opts: ["Amazon ECS", "Amazon EKS", "AWS Fargate", "AWS Lambda", "Amazon Lightsail"], ans: [0, 1, 2], multi: true, explain: "ECS is AWS-native container orchestration, EKS provides managed Kubernetes, and Fargate is a serverless compute engine for containers used with ECS or EKS. Lambda is serverless compute for functions (not containers in the orchestration sense), and Lightsail is a simplified virtual server service." },
  { domain: 3, task: "3.3", q: "An e-commerce company wants to ensure its web tier remains responsive during traffic spikes. Which TWO features of EC2 Auto Scaling help achieve this? (Select TWO)", opts: ["Predictive scaling based on historical traffic patterns", "Target tracking to maintain a specific average CPU utilization", "Multi-Region replication of instance store data", "Automatic migration of instances to larger types", "Manual approval of each new instance launch"], ans: [0, 1], multi: true, explain: "Predictive scaling uses ML to forecast demand and pre-provision capacity before spikes. Target tracking automatically adjusts instance count to maintain a metric like average CPU utilization at a specified value. Auto Scaling does not replicate instance store data or automatically change instance types." },
  { domain: 3, task: "3.4", q: "A company is building a new application and needs to choose appropriate database services. Which of the following are fully managed NoSQL database services on AWS? (Select TWO)", opts: ["Amazon DynamoDB", "Amazon DocumentDB", "Amazon Aurora", "Amazon Redshift", "Amazon RDS for MySQL"], ans: [0, 1], multi: true, explain: "DynamoDB is a managed NoSQL key-value and document database, and DocumentDB is a managed MongoDB-compatible document database. Aurora and RDS for MySQL are relational databases, and Redshift is a data warehouse." },
  { domain: 3, task: "3.4", q: "A company needs to improve the read performance of their Amazon Aurora database and also ensure automatic failover if the primary instance fails. Which TWO features should they configure? (Select TWO)", opts: ["Aurora Read Replicas to offload read traffic", "Multi-AZ deployment for automatic failover", "DynamoDB Accelerator (DAX) for caching", "Aurora Serverless v2 for write scaling", "S3 Cross-Region Replication for backups"], ans: [0, 1], multi: true, explain: "Aurora Read Replicas distribute read traffic across multiple instances to improve performance, and Multi-AZ deployment maintains a standby for automatic failover. DAX is specific to DynamoDB, Aurora Serverless addresses scaling differently, and S3 CRR is for object storage replication." },
  { domain: 3, task: "3.5", q: "A company needs to establish private connectivity between their VPC and AWS services like S3 and DynamoDB without traversing the public internet. Which TWO types of VPC endpoints can they use? (Select TWO)", opts: ["Gateway endpoints", "Interface endpoints (AWS PrivateLink)", "Internet Gateway", "NAT Gateway", "Virtual Private Gateway"], ans: [0, 1], multi: true, explain: "Gateway endpoints provide private access to S3 and DynamoDB via route table entries. Interface endpoints use AWS PrivateLink to create ENIs in your subnet for private connectivity to many AWS services. Internet and NAT Gateways route traffic to the internet, and Virtual Private Gateway is for VPN connections." },
  { domain: 3, task: "3.5", q: "A network engineer is configuring security for a multi-tier application in a VPC. Which TWO statements accurately describe differences between Security Groups and Network ACLs? (Select TWO)", opts: ["Security Groups evaluate all rules before deciding to allow traffic; NACLs process rules in order and stop at the first match", "NACLs support both allow and deny rules; Security Groups support only allow rules", "Security Groups apply at the subnet level; NACLs apply at the instance level", "NACLs are stateful; Security Groups are stateless", "Security Groups and NACLs both operate at Layer 7 of the OSI model"], ans: [0, 1], multi: true, explain: "Security Groups evaluate all rules collectively, while NACLs process rules in numbered order and apply the first matching rule. NACLs support explicit allow and deny rules, whereas Security Groups only have allow rules with an implicit deny-all. Security Groups apply at the instance level (not subnet), and Security Groups are stateful while NACLs are stateless." },
  { domain: 3, task: "3.6", q: "A company wants to implement a cost-effective storage strategy for different data access patterns. Which TWO S3 features help automatically optimize storage costs over time? (Select TWO)", opts: ["S3 Intelligent-Tiering", "S3 Lifecycle Policies", "S3 Versioning", "S3 Transfer Acceleration", "S3 Object Lock"], ans: [0, 1], multi: true, explain: "Intelligent-Tiering automatically moves objects between access tiers based on usage patterns, and Lifecycle Policies transition objects to cheaper storage classes or delete them on a defined schedule. Versioning retains object versions, Transfer Acceleration speeds uploads, and Object Lock prevents deletion." },
  { domain: 3, task: "3.6", q: "A company needs shared file storage accessible from multiple EC2 instances. Which TWO AWS services provide managed file system storage? (Select TWO)", opts: ["Amazon EFS", "Amazon FSx for Windows File Server", "Amazon EBS", "Amazon S3", "AWS Storage Gateway"], ans: [0, 1], multi: true, explain: "EFS provides managed NFS file storage mountable by multiple Linux instances, and FSx for Windows File Server provides managed SMB file storage for Windows workloads. EBS is block storage attached to a single instance, S3 is object storage, and Storage Gateway is a hybrid storage service." },

  // ===== ADDITIONAL SIMPLE QUESTIONS =====
  { domain: 3, task: "3.1", q: "Which AWS service lets you model and provision AWS infrastructure using programming languages like Python or TypeScript?", opts: ["AWS CloudFormation", "AWS CDK", "AWS OpsWorks", "AWS Elastic Beanstalk"], ans: 1, explain: "AWS CDK allows you to define infrastructure using familiar programming languages." },
  { domain: 3, task: "3.1", q: "What does an AWS CloudFormation stack represent?", opts: ["A collection of IAM users", "A group of AWS resources managed as a single unit", "A set of billing alarms", "A list of AMIs"], ans: 1, explain: "A CloudFormation stack is a collection of AWS resources provisioned and managed together." },
  { domain: 3, task: "3.1", q: "Which CloudFormation feature lets you see proposed changes before updating a stack?", opts: ["Stack Policy", "Change Set", "Drift Detection", "Stack Output"], ans: 1, explain: "Change Sets preview how stack modifications will affect existing resources before execution." },
  { domain: 3, task: "3.1", q: "Which AWS service provides a managed Puppet and Chef environment for configuration management?", opts: ["AWS CloudFormation", "AWS OpsWorks", "AWS CodeDeploy", "AWS Systems Manager"], ans: 1, explain: "AWS OpsWorks is a managed configuration management service using Chef and Puppet." },
  { domain: 3, task: "3.1", q: "Which AWS service deploys applications automatically to EC2, Lambda, or on-premises servers?", opts: ["AWS CodeBuild", "AWS CodePipeline", "AWS CodeDeploy", "AWS CodeCommit"], ans: 2, explain: "AWS CodeDeploy automates application deployments to various compute services." },
  { domain: 3, task: "3.1", q: "What is the main benefit of using AWS Elastic Beanstalk?", opts: ["It provides bare-metal server access", "It automatically handles deployment, scaling, and monitoring of web applications", "It stores static website content", "It manages DNS routing"], ans: 1, explain: "Elastic Beanstalk handles infrastructure provisioning, scaling, and monitoring automatically." },
  { domain: 3, task: "3.1", q: "Which AWS service provides a fully managed source control service hosting Git repositories?", opts: ["AWS CodeDeploy", "AWS CodeBuild", "AWS CodeCommit", "AWS CodePipeline"], ans: 2, explain: "AWS CodeCommit is a managed Git-based source control repository service." },
  { domain: 3, task: "3.1", q: "Which service automates the build, test, and deploy phases of a software release pipeline?", opts: ["AWS CodeCommit", "AWS CodePipeline", "AWS CloudFormation", "AWS OpsWorks"], ans: 1, explain: "AWS CodePipeline is a CI/CD service that automates release pipelines end-to-end." },

  { domain: 3, task: "3.2", q: "Which factor determines where AWS builds new Regions?", opts: ["Proximity to AWS headquarters", "Customer demand, compliance needs, and data sovereignty requirements", "Alphabetical order of country names", "Availability of renewable energy only"], ans: 1, explain: "AWS selects Region locations based on customer demand, regulatory requirements, and data residency laws." },
  { domain: 3, task: "3.2", q: "What is the benefit of deploying resources across multiple Availability Zones?", opts: ["Lower pricing per instance", "Protection against a single data center failure", "Faster internet speeds globally", "Automatic code deployment"], ans: 1, explain: "Multi-AZ deployments protect against failures in a single data center location." },
  { domain: 3, task: "3.2", q: "Which AWS infrastructure feature provides ultra-low latency by placing compute at the edge of 5G networks?", opts: ["AWS Local Zones", "AWS Wavelength", "AWS Outposts", "CloudFront Edge Locations"], ans: 1, explain: "AWS Wavelength embeds compute inside 5G networks for single-digit millisecond latency." },
  { domain: 3, task: "3.2", q: "Which AWS service brings native AWS services, infrastructure, and operating models to on-premises data centers?", opts: ["AWS Local Zones", "AWS Direct Connect", "AWS Outposts", "AWS Snow Family"], ans: 2, explain: "AWS Outposts delivers AWS infrastructure and services to any on-premises location." },
  { domain: 3, task: "3.2", q: "What happens to traffic between Availability Zones in the same Region?", opts: ["It travels over the public internet", "It is routed through low-latency private fiber links", "It must go through a VPN gateway", "It is not possible to communicate across AZs"], ans: 1, explain: "AZs within a Region are connected via high-bandwidth, low-latency private fiber networking." },
  { domain: 3, task: "3.2", q: "Which disaster recovery strategy keeps a minimal version of the critical components always running in a secondary Region?", opts: ["Backup and restore", "Pilot light", "Warm standby", "Multi-site active-active"], ans: 1, explain: "Pilot light keeps core systems (e.g., databases) running in a secondary Region at minimal scale." },
  { domain: 3, task: "3.2", q: "What is the purpose of an AWS Local Zone?", opts: ["To provide dedicated hardware for compliance", "To place compute closer to users in specific metro areas", "To extend on-premises networks to AWS", "To provide isolated government cloud environments"], ans: 1, explain: "Local Zones extend AWS infrastructure to metro areas for low-latency applications." },
  { domain: 3, task: "3.2", q: "Which factor should primarily drive your choice of AWS Region for a regulated workload?", opts: ["Proximity to your office", "Data residency and compliance requirements", "Number of available instance types", "CloudFront edge location count"], ans: 1, explain: "Data sovereignty and compliance laws often mandate which Region data must reside in." },
  { domain: 3, task: "3.2", q: "What does RTO stand for in disaster recovery planning?", opts: ["Recovery Transfer Object", "Recovery Time Objective", "Redundant Transfer Operation", "Regional Transfer Output"], ans: 1, explain: "RTO is the maximum acceptable time to restore a system after a disruption." },

  { domain: 3, task: "3.3", q: "Which AWS compute service runs code without provisioning or managing servers?", opts: ["Amazon EC2", "Amazon ECS", "AWS Lambda", "Amazon Lightsail"], ans: 2, explain: "AWS Lambda is a serverless compute service that runs code in response to events." },
  { domain: 3, task: "3.3", q: "What is the maximum execution timeout for an AWS Lambda function?", opts: ["5 minutes", "10 minutes", "15 minutes", "30 minutes"], ans: 2, explain: "Lambda functions can run for a maximum of 15 minutes per invocation." },
  { domain: 3, task: "3.3", q: "Which EC2 pricing model offers the largest discount in exchange for a capacity commitment of 1 or 3 years?", opts: ["On-Demand", "Spot Instances", "Reserved Instances", "Dedicated Hosts"], ans: 2, explain: "Reserved Instances provide up to 72% savings over On-Demand with 1 or 3-year commitments." },
  { domain: 3, task: "3.3", q: "Which EC2 instance purchasing option is best for fault-tolerant, flexible workloads that can withstand interruptions?", opts: ["On-Demand Instances", "Reserved Instances", "Dedicated Instances", "Spot Instances"], ans: 3, explain: "Spot Instances use spare EC2 capacity at steep discounts but can be interrupted by AWS." },
  { domain: 3, task: "3.3", q: "What does Amazon EC2 Auto Scaling do when CPU utilization exceeds a defined threshold?", opts: ["Upgrades existing instances to larger types", "Launches additional EC2 instances", "Moves the workload to Lambda", "Creates a new VPC"], ans: 1, explain: "Auto Scaling launches new instances to handle increased load when thresholds are breached." },
  { domain: 3, task: "3.3", q: "Which service provides simple virtual servers in the cloud with a predictable monthly price, ideal for small workloads?", opts: ["Amazon EC2", "AWS Lambda", "Amazon Lightsail", "AWS Fargate"], ans: 2, explain: "Amazon Lightsail offers easy-to-use virtual servers with bundled pricing for simple use cases." },
  { domain: 3, task: "3.3", q: "Which AWS container service provides managed Kubernetes control plane?", opts: ["Amazon ECS", "Amazon EKS", "AWS Fargate", "AWS Batch"], ans: 1, explain: "Amazon EKS is a managed Kubernetes service that runs the Kubernetes control plane." },
  { domain: 3, task: "3.3", q: "Which compute option lets you run containers without managing the underlying EC2 instances?", opts: ["Amazon ECS on EC2", "AWS Fargate", "Amazon EKS on EC2", "Amazon Lightsail"], ans: 1, explain: "AWS Fargate is a serverless compute engine for containers that removes infrastructure management." },
  { domain: 3, task: "3.3", q: "What is an EC2 placement group used for?", opts: ["Grouping IAM users by role", "Controlling how instances are physically placed to optimize performance or resilience", "Tagging instances for billing", "Assigning Elastic IPs to instances"], ans: 1, explain: "Placement groups influence instance placement to meet latency, throughput, or fault-tolerance needs." },

  { domain: 3, task: "3.4", q: "Which AWS database service is a fully managed, serverless key-value and document NoSQL database?", opts: ["Amazon RDS", "Amazon Aurora", "Amazon DynamoDB", "Amazon Redshift"], ans: 2, explain: "DynamoDB is a fully managed, serverless NoSQL database offering single-digit millisecond performance." },
  { domain: 3, task: "3.4", q: "Which AWS service is a managed relational database that is MySQL and PostgreSQL compatible and offers up to 5x performance of standard MySQL?", opts: ["Amazon RDS", "Amazon Aurora", "Amazon DynamoDB", "Amazon ElastiCache"], ans: 1, explain: "Amazon Aurora is a MySQL/PostgreSQL-compatible relational database with up to 5x MySQL performance." },
  { domain: 3, task: "3.4", q: "Which AWS database service is designed for petabyte-scale data warehousing and analytics?", opts: ["Amazon DynamoDB", "Amazon RDS", "Amazon Redshift", "Amazon Neptune"], ans: 2, explain: "Amazon Redshift is a petabyte-scale cloud data warehouse optimized for analytical queries." },
  { domain: 3, task: "3.4", q: "Which AWS service provides an in-memory caching layer to improve database read performance?", opts: ["Amazon RDS", "Amazon DynamoDB", "Amazon ElastiCache", "Amazon Aurora"], ans: 2, explain: "ElastiCache provides in-memory caching using Redis or Memcached to reduce database load." },
  { domain: 3, task: "3.4", q: "Which AWS service is a fully managed graph database?", opts: ["Amazon Aurora", "Amazon Neptune", "Amazon QLDB", "Amazon Timestream"], ans: 1, explain: "Amazon Neptune is a managed graph database for highly connected datasets." },
  { domain: 3, task: "3.4", q: "What does the RDS Multi-AZ feature primarily provide?", opts: ["Read performance improvements", "Automatic failover for high availability", "Cross-Region replication", "Lower cost storage"], ans: 1, explain: "RDS Multi-AZ maintains a synchronous standby replica for automatic failover." },
  { domain: 3, task: "3.4", q: "Which AWS service provides a managed ledger database with an immutable, cryptographically verifiable transaction log?", opts: ["Amazon Neptune", "Amazon Timestream", "Amazon QLDB", "Amazon DocumentDB"], ans: 2, explain: "Amazon QLDB provides an immutable, cryptographically verifiable ledger for transaction history." },
  { domain: 3, task: "3.4", q: "Which caching service is specifically built to accelerate Amazon DynamoDB read performance?", opts: ["Amazon ElastiCache for Redis", "Amazon ElastiCache for Memcached", "DynamoDB Accelerator (DAX)", "Amazon CloudFront"], ans: 2, explain: "DAX is an in-memory cache designed specifically for DynamoDB with microsecond read latency." },

  { domain: 3, task: "3.5", q: "What is the purpose of an Internet Gateway in a VPC?", opts: ["To connect a VPC to another VPC", "To enable communication between a VPC and the internet", "To provide private connectivity to AWS services", "To filter traffic between subnets"], ans: 1, explain: "An Internet Gateway allows resources in a public subnet to communicate with the internet." },
  { domain: 3, task: "3.5", q: "Which VPC component allows instances in a private subnet to initiate outbound internet traffic?", opts: ["Internet Gateway", "NAT Gateway", "Virtual Private Gateway", "VPC Endpoint"], ans: 1, explain: "A NAT Gateway allows private subnet instances to access the internet without being directly reachable." },
  { domain: 3, task: "3.5", q: "Which AWS networking service connects multiple VPCs and on-premises networks through a central hub?", opts: ["VPC Peering", "AWS Direct Connect", "AWS Transit Gateway", "Internet Gateway"], ans: 2, explain: "AWS Transit Gateway acts as a central hub connecting multiple VPCs and on-premises networks." },
  { domain: 3, task: "3.5", q: "Which AWS service provides a dedicated private connection from an on-premises data center to AWS?", opts: ["AWS VPN", "AWS Direct Connect", "VPC Peering", "AWS Transit Gateway"], ans: 1, explain: "AWS Direct Connect provides a dedicated, private physical connection to AWS." },
  { domain: 3, task: "3.5", q: "A security group rule allows inbound HTTP traffic. Which statement about the return traffic is true?", opts: ["You must add a separate outbound rule to allow return traffic", "Return traffic is automatically allowed because security groups are stateful", "Return traffic is blocked by the NACL", "You must open port 80 outbound explicitly"], ans: 1, explain: "Security groups are stateful; return traffic for allowed connections is automatically permitted." },
  { domain: 3, task: "3.5", q: "Which AWS service acts as a hub to connect multiple VPCs and on-premises networks through a central point?", opts: ["VPC Peering", "AWS Direct Connect", "AWS Transit Gateway", "Elastic Load Balancing"], ans: 2, explain: "AWS Transit Gateway connects VPCs and on-premises networks through a central routing hub." },
  { domain: 3, task: "3.5", q: "What type of load balancer operates at Layer 7 and supports content-based routing?", opts: ["Network Load Balancer", "Classic Load Balancer", "Application Load Balancer", "Gateway Load Balancer"], ans: 2, explain: "Application Load Balancer operates at HTTP/HTTPS (Layer 7) and routes based on content rules." },
  { domain: 3, task: "3.5", q: "Which AWS service provides a global network of edge locations to cache and deliver content with low latency?", opts: ["AWS Global Accelerator", "Amazon Route 53", "Amazon CloudFront", "AWS Direct Connect"], ans: 2, explain: "CloudFront is a CDN that caches content at edge locations for low-latency delivery." },
  { domain: 3, task: "3.5", q: "Which Route 53 routing policy directs traffic to the endpoint with the lowest network latency for the user?", opts: ["Weighted routing", "Failover routing", "Latency-based routing", "Geolocation routing"], ans: 2, explain: "Latency-based routing directs users to the AWS Region with the lowest network latency." },

  { domain: 3, task: "3.6", q: "Which S3 storage class is designed for data that is accessed less than once a month and requires rapid retrieval?", opts: ["S3 Standard", "S3 Standard-IA", "S3 One Zone-IA", "S3 Glacier Instant Retrieval"], ans: 3, explain: "S3 Glacier Instant Retrieval is for rarely accessed archive data needing millisecond retrieval." },
  { domain: 3, task: "3.6", q: "What is the durability guarantee for objects stored in Amazon S3?", opts: ["99.9%", "99.99%", "99.999999999% (11 nines)", "99.9999999% (9 nines)"], ans: 2, explain: "S3 is designed for 99.999999999% (11 nines) durability by redundantly storing objects." },
  { domain: 3, task: "3.6", q: "Which EBS volume type provides the highest IOPS performance for latency-sensitive workloads?", opts: ["gp2", "st1", "sc1", "io2"], ans: 3, explain: "io2 Provisioned IOPS SSD volumes deliver the highest and most consistent IOPS performance." },
  { domain: 3, task: "3.6", q: "What is the key difference between Amazon EBS and Amazon EFS?", opts: ["EBS supports object storage; EFS supports block storage", "EBS is block storage for a single instance; EFS is a shared file system for multiple instances", "EBS is serverless; EFS requires EC2", "EBS supports Windows only; EFS supports Linux only"], ans: 1, explain: "EBS attaches as block storage to one instance; EFS is a shared NFS file system for many instances." },
  { domain: 3, task: "3.6", q: "Which S3 feature prevents objects from being deleted or overwritten for a defined retention period?", opts: ["S3 Versioning", "S3 Replication", "S3 Object Lock", "S3 Lifecycle Policy"], ans: 2, explain: "S3 Object Lock enforces WORM (write-once-read-many) protection for a specified retention period." },
  { domain: 3, task: "3.6", q: "Which AWS Snow Family device is the smallest and most portable option for edge compute and data transfer?", opts: ["AWS Snowball Edge", "AWS Snowmobile", "AWS Snowcone", "AWS DataSync"], ans: 2, explain: "Snowcone is the smallest Snow Family device, weighing under 5 lbs, for edge and transfer tasks." },
  { domain: 3, task: "3.6", q: "What is the purpose of S3 Transfer Acceleration?", opts: ["To automatically move objects to cheaper storage tiers", "To speed up uploads to S3 by routing through CloudFront edge locations", "To replicate S3 objects to another Region", "To encrypt objects at rest in S3"], ans: 1, explain: "Transfer Acceleration uses CloudFront edge locations to accelerate long-distance S3 uploads." },
  { domain: 3, task: "3.6", q: "Which AWS storage service is best suited for storing and retrieving large amounts of unstructured data via a web API?", opts: ["Amazon EBS", "Amazon EFS", "Amazon S3", "Amazon FSx"], ans: 2, explain: "Amazon S3 is an object storage service designed for scalable unstructured data via HTTP APIs." }
